//! Golden test implementations for fmridesign-rs
//! 
//! These tests validate the Rust implementation against golden test specifications
//! that ensure cross-language compatibility and mathematical correctness.

use fmridesign_rs::{
    basis::{BSplineBasis, BasisFunction, PolynomialBasis},
    baseline::{BaselineModel, BaselineSpec},
    design::{DesignMatrix, DesignMatrixBuilder},
    events::{EventFactor, EventVariable},
    sampling::SamplingFrame,
    core::EventModel,
    formula::Formula,
    types::EventSpec,
    error::Result,
};
use ndarray::{Array1, Array2};
use approx::assert_abs_diff_eq;

/// Helper function to create a sampling frame for tests
fn create_test_sampling_frame(block_lengths: &[usize], tr: f64) -> SamplingFrame {
    SamplingFrame::new(block_lengths.to_vec(), tr).expect("Valid sampling frame")
}

/// Helper function to validate design matrix dimensions
fn validate_dimensions(matrix: &DesignMatrix, expected_rows: usize, expected_cols: usize) {
    assert_eq!(matrix.data().nrows(), expected_rows, "Incorrect number of rows");
    assert_eq!(matrix.data().ncols(), expected_cols, "Incorrect number of columns");
}

/// Helper function to check non-negativity of matrix columns
fn check_non_negativity(matrix: &Array2<f64>, columns: &[usize], tolerance: f64) {
    for &col in columns {
        let min_val = matrix.column(col).iter().fold(f64::INFINITY, |a, &b| a.min(b));
        assert!(min_val >= -tolerance, 
            "Column {} has negative values: min = {}", col, min_val);
    }
}

/// Helper function to check row sums
fn check_row_sum(matrix: &Array2<f64>, row: usize, columns: &[usize], expected: f64, tolerance: f64) {
    let sum: f64 = columns.iter().map(|&col| matrix[[row, col]]).sum();
    assert_abs_diff_eq!(sum, expected, epsilon = tolerance,
        "Row {} sum mismatch: expected {}, got {}", row, expected, sum);
}

/// Helper function to check column sums
fn check_column_sum(matrix: &Array2<f64>, col: usize, expected: f64, tolerance: f64) {
    let sum: f64 = matrix.column(col).sum();
    assert_abs_diff_eq!(sum, expected, epsilon = tolerance,
        "Column {} sum mismatch: expected {}, got {}", col, expected, sum);
}

#[test]
fn golden_test_basis_functions_bspline_invariants() {
    // golden-test-id: basis_functions_bspline_invariants

    // Create sampling frame: 80 time points, TR=2.0
    let sframe = create_test_sampling_frame(&[80], 2.0);

    // Create baseline model with B-spline basis, degree 5
    let baseline_spec = BaselineSpec::BSpline { 
        degree: 5, 
        intercept: true 
    };
    let baseline = BaselineModel::new(sframe.clone(), baseline_spec)
        .expect("Failed to create baseline model");

    // Get design matrix
    let dm = baseline.design_matrix().expect("Failed to get design matrix");

    // Validate dimensions: 80 rows, 6 columns (5 B-spline + 1 intercept)
    validate_dimensions(&dm, 80, 6);

    let matrix = dm.data();

    // 1. NON-NEGATIVITY: All B-spline values must be ≥ 0
    check_non_negativity(matrix, &[0, 1, 2, 3, 4], 0.001);

    // 2. PARTITION OF UNITY: B-spline basis functions sum to 1 in interior
    // (Note: B-splines only satisfy partition of unity in interior, not at boundaries)
    check_row_sum(matrix, 50, &[0, 1, 2, 3, 4], 1.0, 0.01);  // t=51
    check_row_sum(matrix, 60, &[0, 1, 2, 3, 4], 1.0, 0.001); // t=61  
    check_row_sum(matrix, 70, &[0, 1, 2, 3, 4], 1.0, 0.001); // t=71

    // 3. BOUNDARY CONDITIONS: Sum should be 0 at first time point
    check_row_sum(matrix, 0, &[0, 1, 2, 3, 4], 0.0, 0.001);

    // 4. LOCAL SUPPORT: Check maximum values are within expected bounds
    let max_col0 = matrix.column(0).iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));
    let max_col2 = matrix.column(2).iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));

    assert_abs_diff_eq!(max_col0, 0.410, epsilon = 0.01, "First B-spline max out of bounds");
    assert_abs_diff_eq!(max_col2, 0.346, epsilon = 0.01, "Middle B-spline max out of bounds");

    // 5. BOUNDARY BEHAVIOR: Specific boundary values
    assert_abs_diff_eq!(matrix[[79, 0]], 0.0, epsilon = 0.001, "First B-spline boundary condition at end");
    assert_abs_diff_eq!(matrix[[0, 4]], 0.0, epsilon = 0.001, "Last B-spline boundary condition at start");

    // 6. INTERCEPT VALIDATION: Global intercept should be constant
    check_column_sum(matrix, 5, 80.0, 0.001);

    // 7. NUMERICAL STABILITY: Check variance of basis function
    let col1_mean = matrix.column(1).mean().unwrap();
    let col1_var = matrix.column(1).iter()
        .map(|&x| (x - col1_mean).powi(2))
        .sum::<f64>() / 80.0;
    let col1_std = col1_var.sqrt();

    assert_abs_diff_eq!(col1_std, 0.126, epsilon = 0.01, "B-spline variance out of expected range");
}

#[test] 
fn golden_test_basis_functions_orthogonal_polynomials() {
    // golden-test-id: basis_functions_orthogonal_polynomials

    // Create sampling frame: 50 time points, TR=2.0
    let sframe = create_test_sampling_frame(&[50], 2.0);

    // Create baseline model with orthogonal polynomial basis, degree 3
    let baseline_spec = BaselineSpec::Polynomial { 
        degree: 3, 
        orthogonal: true, 
        intercept: true 
    };
    let baseline = BaselineModel::new(sframe.clone(), baseline_spec)
        .expect("Failed to create baseline model");

    let dm = baseline.design_matrix().expect("Failed to get design matrix");

    // Validate dimensions: 50 rows, 4 columns (3 polynomial + 1 intercept)
    validate_dimensions(&dm, 50, 4);

    let matrix = dm.data();

    // 1. ORTHOGONALITY: Polynomial columns should be orthogonal (dot product ≈ 0)
    for i in 0..3 {
        for j in (i+1)..3 {
            let dot_product: f64 = (0..50).map(|row| matrix[[row, i]] * matrix[[row, j]]).sum();
            assert_abs_diff_eq!(dot_product, 0.0, epsilon = 0.001,
                "Polynomial columns {} and {} are not orthogonal: dot product = {}", i, j, dot_product);
        }
    }

    // 2. NORMALIZATION: Each polynomial column should have unit norm (sum of squares = 1)
    for i in 0..3 {
        let norm_sq: f64 = (0..50).map(|row| matrix[[row, i]].powi(2)).sum();
        assert_abs_diff_eq!(norm_sq, 1.0, epsilon = 0.001,
            "Polynomial column {} norm squared = {}, expected 1.0", i, norm_sq);
    }

    // 3. INTERCEPT: Should be constant (all 1s)
    check_column_sum(matrix, 3, 50.0, 0.001);
    for row in 0..50 {
        assert_abs_diff_eq!(matrix[[row, 3]], 1.0, epsilon = 0.001,
            "Intercept at row {} is not 1.0", row);
    }
}

#[test]
fn golden_test_event_model_basic_hrf() {
    // golden-test-id: event_model_basic_hrf

    // Create sampling frame: 100 time points, TR=2.0  
    let sframe = create_test_sampling_frame(&[100], 2.0);

    // Create events for two conditions A and B
    let mut events = Vec::new();
    events.push((10.0, "A".to_string(), 1, 0.0)); // onset=10s, condition=A, block=1, duration=0
    events.push((30.0, "B".to_string(), 1, 0.0)); // onset=30s, condition=B, block=1, duration=0  
    events.push((60.0, "A".to_string(), 1, 0.0)); // onset=60s, condition=A, block=1, duration=0
    events.push((80.0, "B".to_string(), 1, 0.0)); // onset=80s, condition=B, block=1, duration=0

    // Create event factor from the events
    let event_factor = EventFactor::from_events(&events, &sframe)
        .expect("Failed to create event factor");

    // Create event model with canonical HRF
    let event_model = EventModel::new(event_factor.into(), &sframe)
        .expect("Failed to create event model");

    let dm = event_model.design_matrix().expect("Failed to get design matrix");

    // Validate dimensions: 100 rows, 2 columns (condition A and B)
    validate_dimensions(&dm, 100, 2);

    let matrix = dm.data();

    // 1. PEAK TIMING: HRF peaks should occur ~5-6 seconds (2.5-3 TRs) after event onset
    // For event at t=10s (TR=5), peak should be around TR=7-8 (t=14-16s)
    let col_a_peak_idx = (0..100).max_by_key(|&i| matrix[[i, 0]] as i64).unwrap();
    let peak_time_a = col_a_peak_idx as f64 * 2.0; // Convert TR to seconds
    assert!((peak_time_a - 10.0) >= 4.0 && (peak_time_a - 10.0) <= 8.0,
        "Condition A peak timing incorrect: peak at {}s, expected 4-8s after onset", peak_time_a - 10.0);

    // 2. RESPONSE MAGNITUDE: Peak responses should be positive and reasonable
    let peak_val_a = matrix[[col_a_peak_idx, 0]];
    assert!(peak_val_a > 0.5 && peak_val_a < 2.0,
        "Condition A peak value out of range: {}", peak_val_a);

    // 3. BASELINE: Values before first event should be near zero
    for row in 0..4 { // First 4 TRs (0-8s) before first event at 10s
        assert!(matrix[[row, 0]].abs() < 0.1, 
            "Condition A baseline not near zero at TR {}: {}", row, matrix[[row, 0]]);
        assert!(matrix[[row, 1]].abs() < 0.1,
            "Condition B baseline not near zero at TR {}: {}", row, matrix[[row, 1]]);
    }

    // 4. UNDERSHOOT: HRF should show undershoot after peak
    let undershoot_idx = col_a_peak_idx + 10; // Look 10 TRs after peak
    if undershoot_idx < 100 {
        assert!(matrix[[undershoot_idx, 0]] < peak_val_a * 0.5,
            "No clear undershoot detected for condition A");
    }
}

#[test]
fn golden_test_baseline_model_polynomial_drift() {
    // golden-test-id: baseline_model_polynomial_drift

    // Create sampling frame: 120 time points, TR=2.0
    let sframe = create_test_sampling_frame(&[120], 2.0);

    // Create baseline model with polynomial drift, degree 2
    let baseline_spec = BaselineSpec::Polynomial { 
        degree: 2, 
        orthogonal: false, 
        intercept: true 
    };
    let baseline = BaselineModel::new(sframe.clone(), baseline_spec)
        .expect("Failed to create baseline model");

    let dm = baseline.design_matrix().expect("Failed to get design matrix");

    // Validate dimensions: 120 rows, 3 columns (constant, linear, quadratic)
    validate_dimensions(&dm, 120, 3);

    let matrix = dm.data();

    // 1. CONSTANT TERM: Should be all 1s
    check_column_sum(matrix, 0, 120.0, 0.001);
    for row in 0..120 {
        assert_abs_diff_eq!(matrix[[row, 0]], 1.0, epsilon = 0.001,
            "Constant term at row {} is not 1.0", row);
    }

    // 2. LINEAR TERM: Should be monotonically increasing
    for row in 1..120 {
        assert!(matrix[[row, 1]] > matrix[[row-1, 1]],
            "Linear term not monotonically increasing at row {}", row);
    }

    // 3. QUADRATIC TERM: Should show quadratic growth
    let start_val = matrix[[0, 2]];
    let mid_val = matrix[[60, 2]];
    let end_val = matrix[[119, 2]];

    // Quadratic should grow faster than linear
    assert!(end_val > mid_val * 1.5,
        "Quadratic term not showing expected growth pattern");

    // 4. RANGE: Polynomial terms should be properly scaled
    let linear_range = matrix.column(1).iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b)) -
                      matrix.column(1).iter().fold(f64::INFINITY, |a, &b| a.min(b));
    assert!(linear_range > 0.1, "Linear term range too small: {}", linear_range);
}

#[test]
fn golden_test_core_design_matrix_conditioning() {
    // golden-test-id: core_design_matrix_conditioning

    // Create a complex design matrix to test conditioning
    let sframe = create_test_sampling_frame(&[100], 2.0);

    // Create both baseline and event components
    let baseline_spec = BaselineSpec::Polynomial { 
        degree: 3, 
        orthogonal: true, 
        intercept: true 
    };
    let baseline = BaselineModel::new(sframe.clone(), baseline_spec)
        .expect("Failed to create baseline model");

    // Create events
    let mut events = Vec::new();
    for i in 0..10 {
        events.push((i as f64 * 10.0, "condition".to_string(), 1, 2.0));
    }

    let event_factor = EventFactor::from_events(&events, &sframe)
        .expect("Failed to create event factor");
    let event_model = EventModel::new(event_factor.into(), &sframe)
        .expect("Failed to create event model");

    // Combine baseline and events
    let mut builder = DesignMatrixBuilder::new(sframe.clone());
    builder.add_baseline(baseline).expect("Failed to add baseline");
    builder.add_event_model(event_model).expect("Failed to add event model");

    let dm = builder.build().expect("Failed to build design matrix");
    let matrix = dm.data();

    // 1. RANK: Matrix should be full rank (not singular)
    let condition_number = calculate_condition_number(matrix);
    assert!(condition_number < 1e12, 
        "Design matrix is poorly conditioned: condition number = {}", condition_number);

    // 2. NO PERFECT MULTICOLLINEARITY: No column should be a linear combination of others
    // This is implicitly tested by the condition number check

    // 3. REASONABLE SCALE: All columns should have reasonable variance
    for col in 0..matrix.ncols() {
        let col_data = matrix.column(col);
        let mean = col_data.mean().unwrap();
        let variance = col_data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / matrix.nrows() as f64;

        assert!(variance > 1e-10, "Column {} has near-zero variance: {}", col, variance);
        assert!(variance < 1e10, "Column {} has excessive variance: {}", col, variance);
    }
}

/// Helper function to calculate condition number (simplified approximation)
fn calculate_condition_number(matrix: &Array2<f64>) -> f64 {
    // For a proper condition number, we'd need SVD
    // This is a simplified approximation using column norms
    let mut min_norm = f64::INFINITY;
    let mut max_norm = 0.0;

    for col in 0..matrix.ncols() {
        let norm = matrix.column(col).iter().map(|&x| x * x).sum::<f64>().sqrt();
        min_norm = min_norm.min(norm);
        max_norm = max_norm.max(norm);
    }

    if min_norm > 0.0 {
        max_norm / min_norm
    } else {
        f64::INFINITY
    }
}

