//! Core data structures for fmridesign.

use crate::types::{ValidationError, EventSpec, EventType, BasisFunction};
use crate::hrf;
use fmrihrf::{SamplingFrame, Hrf};
use ndarray::{Array1, Array2, ArrayView1, Axis};
use std::collections::HashMap;
use std::fmt;

/// Main model struct that holds all events and generates design matrices.
#[derive(Debug)]
pub struct EventModel {
    /// List of events in the model
    pub events: Vec<Box<dyn EventSpec>>,
    /// Sampling frame
    pub sampling_frame: SamplingFrame,
    /// Name for the model
    pub name: String,
}

impl EventModel {
    /// Create a new EventModel.
    pub fn new(events: Vec<Box<dyn EventSpec>>, sampling_frame: SamplingFrame) -> Result<Self, ValidationError> {
        if events.is_empty() {
            return Err(ValidationError::InvalidParameter("EventModel requires at least one event".to_string()));
        }

        Ok(EventModel {
            events,
            sampling_frame,
            name: "EventModel".to_string(),
        })
    }

    /// Generate the design matrix.
    pub fn generate_design_matrix(&self) -> Result<Array2<f64>, ValidationError> {
        self.generate_design_matrix_impl(false)
    }

    /// Generate the design matrix with caching.
    pub fn generate_design_matrix_cached(&self) -> Result<Array2<f64>, ValidationError> {
        self.generate_design_matrix_impl(true)
    }

    /// Internal implementation of design matrix generation.
    fn generate_design_matrix_impl(&self, use_cache: bool) -> Result<Array2<f64>, ValidationError> {
        let mut columns = Vec::new();
        let mut column_names = Vec::new();

        // Get sampling points
        let sampling_points_vec = self.sampling_frame.samples();
        let n_samples = sampling_points_vec.len();
        let sampling_points = Array1::from_vec(sampling_points_vec);

        // Generate columns for each event
        for event in &self.events {
            let event_matrix = if use_cache {
                // Use cached computation
                self.generate_event_matrix_cached(event.as_ref(), &sampling_points)?
            } else {
                // Direct computation
                event.design_matrix(&sampling_points)?
            };

            let event_names = event.column_names();

            // Ensure correct dimensions
            if event_matrix.nrows() != n_samples {
                return Err(ValidationError::DimensionError {
                    expected: n_samples,
                    actual: event_matrix.nrows(),
                });
            }

            // Add columns
            for i in 0..event_matrix.ncols() {
                columns.push(event_matrix.column(i).to_owned());
                column_names.push(event_names.get(i).cloned().unwrap_or_else(|| format!("col_{}", i)));
            }
        }

        // Combine all columns into design matrix
        if columns.is_empty() {
            return Ok(Array2::zeros((n_samples, 0)));
        }

        let n_cols = columns.len();
        let mut design_matrix = Array2::zeros((n_samples, n_cols));

        for (i, col) in columns.into_iter().enumerate() {
            design_matrix.column_mut(i).assign(&col);
        }

        Ok(design_matrix)
    }

    /// Get column names for the design matrix.
    pub fn column_names(&self) -> Vec<String> {
        let mut names = Vec::new();
        for event in &self.events {
            names.extend(event.column_names());
        }
        names
    }

    /// Get the number of columns in the design matrix.
    pub fn n_columns(&self) -> usize {
        self.events.iter().map(|e| e.n_columns().unwrap_or(1)).sum()
    }

    /// Get the number of samples.
    pub fn n_samples(&self) -> usize {
        self.sampling_frame.n_scans()
    }

    /// Get a reference to the events.
    pub fn events(&self) -> &[Box<dyn EventSpec>] {
        &self.events
    }

    /// Get the number of events.
    pub fn n_events(&self) -> usize {
        self.events.len()
    }

    /// Add an event to the model.
    pub fn add_event(&mut self, event: Box<dyn EventSpec>) {
        self.events.push(event);
    }

    /// Set the model name.
    pub fn with_name(mut self, name: impl Into<String>) -> Self {
        self.name = name.into();
        self
    }

    /// Generate event matrix with caching.
    fn generate_event_matrix_cached(
        &self,
        event: &dyn EventSpec,
        sampling_points: &Array1<f64>,
    ) -> Result<Array2<f64>, ValidationError> {
        use crate::cache::{cached_design_matrix, hash_array};
        use std::collections::hash_map::DefaultHasher;
        use std::hash::{Hash, Hasher};

        // Create a hash of event parameters
        let mut hasher = DefaultHasher::new();
        event.name().hash(&mut hasher);
        event.event_type().hash(&mut hasher);

