//! fmridesign - Rust implementation of fMRI experimental design matrices
//!
//! This crate provides tools for constructing design matrices for fMRI experiments,
//! including event specifications, basis functions, HRF convolution, and contrast
//! definitions.
//!
//! # Example
//!
//! ```ignore
//! use fmridesign::prelude::*;
//! 
//! // Create an event specification
//! let event = EventFactor::new("stimulus")
//!     .onsets(vec![0.0, 10.0, 20.0])
//!     .durations(vec![1.0, 1.0, 1.0])
//!     .build()?;
//!
//! // Create a model and generate design matrix
//! let model = EventModel::new()
//!     .add_event(event)
//!     .sampling_rate(0.5)
//!     .build()?;
//!
//! let design_matrix = model.design_matrix()?;
//! ```

