/// Create an event table from multiple events.
///
/// Combines multiple events into a single DataFrame for easy inspection
/// and manipulation.
///
/// # Arguments
/// * `events` - Vector of event specifications
///
/// # Returns
/// A DataFrame with columns for event name, onset, duration, and event-specific values
///
/// # Example
/// ```ignore
/// let events = vec![
///     Box::new(Event::new("cue", vec![1.0, 3.0, 5.0])),
///     Box::new(EventVariable::new("rating", vec![2.0, 4.0], vec![7.5, 3.2], vec![1.0, 1.0])?),
/// ];
/// let table = event_table(events)?;
/// ```
pub fn event_table(events: Vec<Box<dyn EventSpec>>) -> Result<DataFrame, ValidationError> {
    let mut df = DataFrame::new();
    let mut all_onsets = Vec::new();
    let mut all_durations = Vec::new();
    let mut all_event_names = Vec::new();
    let mut all_event_types = Vec::new();

    // Collect data from all events
    for event in &events {
        let n_events = event.n_events();
        let onsets = event.onsets();
        let durations = event.durations();

        // Add to combined vectors
        all_onsets.extend(onsets.iter().cloned());
        all_durations.extend(durations.iter().cloned());
        all_event_names.extend(vec![event.name().to_string(); n_events]);
        all_event_types.extend(vec![format!("{:?}", event.event_type()); n_events]);

        // Handle event-specific data
        if let Some(levels) = event.levels() {
            // For categorical events, add level information
            if let Some(values) = event.values() {
                // We'll need to track these separately and merge later
            }
        }
    }

    // Sort by onset time first
    let mut indices: Vec<usize> = (0..all_onsets.len()).collect();
    indices.sort_by(|&a, &b| {
        all_onsets[a].partial_cmp(&all_onsets[b]).unwrap()
    });

    // Create sorted data
    let sorted_onsets: Vec<f64> = indices.iter().map(|&i| all_onsets[i]).collect();
    let sorted_durations: Vec<f64> = indices.iter().map(|&i| all_durations[i]).collect();
    let sorted_names: Vec<String> = indices.iter().map(|&i| all_event_names[i].clone()).collect();
    let sorted_types: Vec<String> = indices.iter().map(|&i| all_event_types[i].clone()).collect();

    // Build the DataFrame with sorted data
    df.add_column("event", sorted_names.iter().map(|s| s.parse().unwrap_or(0.0)).collect())?;
    df.add_column("onset", sorted_onsets)?;
    df.add_column("duration", sorted_durations)?;
    df.add_str_column("event_name", sorted_names)?;
    df.add_str_column("event_type", sorted_types)?;

    Ok(df)
}

