     1→//! Continuous event implementation.
     2→
     3→use ndarray::{Array1, Array2};
     4→use crate::types::{EventSpec, EventType, OnsetArray, DurationArray, Array, ValidationError, validate_onsets, validate_durations};
     5→
     6→/// Continuous event with numeric values.
     7→///
     8→/// This represents events with continuous values (ratings, reaction times,
     9→/// parametric modulators, etc.) in an fMRI experiment.
    10→#[derive(Debug, Clone)]
    11→pub struct EventVariable {
    12→    /// Event name
    13→    pub name: String,
    14→    /// Event onset times
    15→    pub onsets: OnsetArray,
    16→    /// Event durations
    17→    pub durations: DurationArray,
    18→    /// Transformed values (after centering/scaling)
    19→    pub values: Array1<f64>,
    20→    /// Raw values (before transformation)
    21→    pub raw_values: Array1<f64>,
    22→    /// Whether values are centered
    23→    pub center: bool,
    24→    /// Whether values are scaled
    25→    pub scale: bool,
    26→}
    27→
    28→impl EventVariable {
    29→    /// Create a new continuous event.
    30→    ///
    31→    /// # Arguments
    32→    /// * `name` - Name of the event
    33→    /// * `onsets` - Event onset times
    34→    /// * `values` - Continuous values for each event
    35→    /// * `durations` - Event durations
    36→    ///
    37→    /// # Example
    38→    /// ```
    39→    /// use fmridesign::events::EventVariable;
    40→    /// 
    41→    /// let event = EventVariable::new(
    42→    ///     "rating",
    43→    ///     vec![1.0, 2.0, 3.0, 4.0],
    44→    ///     vec![7.5, 3.2, 8.1, 5.5],
    45→    ///     vec![1.0, 1.0, 1.0, 1.0],
    46→    /// ).unwrap();
    47→    /// ```
    48→    pub fn new<S: Into<String>>(
    49→        name: S,
    50→        onsets: Vec<f64>,
    51→        values: Vec<f64>,
    52→        durations: Vec<f64>,
    53→    ) -> Result<Self, ValidationError> {
    54→        let name = name.into();
    55→        let onsets = validate_onsets(onsets)?;
    56→        let durations = validate_durations(durations, onsets.len())?;
    57→        
    58→        // Validate values
    59→        if values.len() != onsets.len() {
    60→            return Err(ValidationError::LengthMismatch {
    61→                expected: onsets.len(),
    62→                actual: values.len(),
    63→            });
    64→        }
    65→        
    66→        let raw_values = Array1::from_vec(values);
    67→        
    68→        // Check for finite values
    69→        if raw_values.iter().any(|&x| !x.is_finite()) {
    70→            return Err(ValidationError::NonFiniteValues);
    71→        }
    72→        
    73→        // By default, center but don't scale
    74→        let transformed_values = Self::transform_values(&raw_values, true, false);
    75→        
    76→        Ok(Self {
    77→            name,
    78→            onsets,
    79→            durations,
    80→            values: transformed_values,
    81→            raw_values,
    82→            center: true,
    83→            scale: false,
    84→        })
    85→    }
    86→    
    87→    /// Set whether to center values (subtract mean).
    88→    pub fn with_center(mut self, center: bool) -> Self {
    89→        self.center = center;
    90→        self.values = Self::transform_values(&self.raw_values, center, self.scale);
    91→        self
    92→    }
    93→    
    94→    /// Set whether to scale values (divide by std).
    95→    pub fn with_scale(mut self, scale: bool) -> Self {
    96→        self.scale = scale;
    97→        self.values = Self::transform_values(&self.raw_values, self.center, scale);
    98→        self
    99→    }
   100→    
   101→    /// Apply centering and/or scaling to values.
   102→    fn transform_values(values: &Array1<f64>, center: bool, scale: bool) -> Array1<f64> {
   103→        let mut result = values.clone();
   104→        
   105→        if center {
   106→            let mean = values.mean().unwrap_or(0.0);
   107→            result = result - mean;
   108→        }
   109→        
   110→        if scale {
   111→            let std = result.std(0.0);
   112→            if std > 0.0 {
   113→                result = result / std;
   114→            } else {
   115→                // All values are the same
   116→                result.fill(0.0);
   117→            }
   118→        }
   119→        
   120→        result
   121→    }
   122→    
   123→    /// Mean of raw values.
   124→    pub fn mean(&self) -> f64 {
   125→        self.raw_values.mean().unwrap_or(0.0)
   126→    }
   127→    
   128→    /// Standard deviation of raw values.
   129→    pub fn std(&self) -> f64 {
   130→        self.raw_values.std(0.0)
   131→    }
   132→    
   133→    /// Minimum of raw values.
   134→    pub fn min(&self) -> f64 {
   135→        self.raw_values.iter().cloned().fold(f64::INFINITY, f64::min)
   136→    }
   137→    
   138→    /// Maximum of raw values.
   139→    pub fn max(&self) -> f64 {
   140→        self.raw_values.iter().cloned().fold(f64::NEG_INFINITY, f64::max)
   141→    }
   142→    
   143→    /// Bin continuous values into discrete categories.
   144→    ///
   145→    /// # Arguments
   146→    /// * `n_bins` - Number of bins to create
   147→    /// * `method` - Binning method: "equal_width", "equal_frequency", or "custom"
   148→    /// * `custom_bins` - Custom bin edges (only used if method is "custom")
   149→    ///
   150→    /// # Returns
   151→    /// A new EventFactor with binned values
   152→    ///
   153→    /// # Example
   154→    /// ```ignore
   155→    /// // Equal width binning
   156→    /// let binned = event.bin_values(3, "equal_width", None)?;
   157→    /// 
   158→    /// // Custom bin edges
   159→    /// let binned = event.bin_values(0, "custom", Some(vec![0.0, 2.5, 5.0, 7.5, 10.0]))?;
   160→    /// ```
   161→    pub fn bin_values(
   162→        &self,
   163→        n_bins: usize,
   164→        method: &str,
   165→        custom_bins: Option<Vec<f64>>,
   166→    ) -> Result<crate::events::EventFactor, ValidationError> {
   167→        use crate::events::EventFactor;
   168→        
   169→        let bin_edges = match method {
   170→            "equal_width" => {
   171→                if n_bins == 0 {
   172→                    return Err(ValidationError::InvalidParameter(
   173→                        "n_bins must be > 0 for equal_width binning".to_string()
   174→                    ));
   175→                }
   176→                
   177→                let min_val = self.min();
   178→                let max_val = self.max();
   179→                let width = (max_val - min_val) / n_bins as f64;
   180→                
   181→                (0..=n_bins)
   182→                    .map(|i| min_val + i as f64 * width)
   183→                    .collect::<Vec<_>>()
   184→            }
   185→            "equal_frequency" | "quantile" => {
   186→                if n_bins == 0 {
   187→                    return Err(ValidationError::InvalidParameter(
   188→                        "n_bins must be > 0 for quantile binning".to_string()
   189→                    ));
   190→                }
   191→                
   192→                // Sort values
   193→                let mut sorted_values = self.raw_values.to_vec();
   194→                sorted_values.sort_by(|a, b| a.partial_cmp(b).unwrap());
   195→                
   196→                // Calculate quantile positions
   197→                let mut edges = vec![sorted_values[0]];
   198→                for i in 1..n_bins {
   199→                    let pos = (i as f64 / n_bins as f64 * sorted_values.len() as f64) as usize;
   200→                    let pos = pos.min(sorted_values.len() - 1);
   201→                    edges.push(sorted_values[pos]);
   202→                }
   203→                edges.push(sorted_values[sorted_values.len() - 1]);
   204→                
   205→                // Remove duplicates and sort
   206→                edges.sort_by(|a, b| a.partial_cmp(b).unwrap());
   207→                edges.dedup();
   208→                edges
   209→            }
   210→            "custom" => {
   211→                custom_bins.ok_or_else(|| ValidationError::InvalidParameter(
   212→                    "custom_bins required for custom binning method".to_string()
   213→                ))?
   214→            }
   215→            _ => {
   216→                return Err(ValidationError::InvalidParameter(
   217→                    format!("Unknown binning method: {}", method)
   218→                ));
   219→            }
   220→        };
   221→        
   222→        // Assign values to bins
   223→        let bin_labels: Vec<String> = self.raw_values.iter()
   224→            .map(|&val| {
   225→                // Find which bin this value belongs to
   226→                let bin_idx = bin_edges.windows(2)
   227→                    .position(|w| val >= w[0] && val < w[1])
   228→                    .or_else(|| {
   229→                        // Handle the last bin (inclusive on both ends)
   230→                        if val == bin_edges[bin_edges.len() - 1] {
   231→                            Some(bin_edges.len() - 2)
   232→                        } else {
   233→                            None
   234→                        }
   235→                    })
   236→                    .unwrap_or(0);
   237→                
   238→                // Create bin label
   239→                if bin_edges.len() > 1 && bin_idx < bin_edges.len() - 1 {
   240→                    format!("bin{}_[{:.2},{:.2})", bin_idx + 1, bin_edges[bin_idx], bin_edges[bin_idx + 1])
   241→                } else {
   242→                    format!("bin{}", bin_idx + 1)
   243→                }
   244→            })
   245→            .collect();
   246→        
   247→        // Create EventFactor with binned values
