     7→
     8→/// Multi-column event representation.
     9→///
    10→/// This represents events with multiple simultaneous values, such as
    11→/// multi-dimensional parametric modulators or pre-computed design columns.
    12→#[derive(Debug, Clone)]
    13→pub struct EventMatrix {
    14→    name: String,
    15→    onsets: OnsetArray,
    16→    durations: DurationArray,
    17→    values: Array2<f64>,
