    19→}
    20→
    21→impl EventMatrix {
    22→    /// Create a new multi-column event.
    23→    ///
    24→    /// # Arguments
    25→    /// * `name` - Name of the event
    26→    /// * `onsets` - Event onset times
    27→    /// * `values` - Matrix of values, shape (n_events, n_columns)
    28→    /// * `durations` - Event durations
    29→    ///
    30→    /// # Example
    31→    /// ```
    32→    /// use fmridesign::events::EventMatrix;
    33→    /// use ndarray::array;
    34→    /// 
    35→    /// let values = array![[0.1, 0.2, 0.3],
    36→    ///                     [0.2, 0.1, 0.4],
    37→    ///                     [0.3, 0.3, 0.2],
    38→    ///                     [0.1, 0.4, 0.3]];
    39→    /// 
    40→    /// let event = EventMatrix::new(
    41→    ///     "motion",
    42→    ///     vec![1.0, 2.0, 3.0, 4.0],
    43→    ///     values,
    44→    ///     vec![1.0, 1.0, 1.0, 1.0],
    45→    /// ).unwrap();
    46→    /// ```
    47→    pub fn new<S: Into<String>>(
    48→        name: S,
    49→        onsets: Vec<f64>,
    50→        values: Array2<f64>,
    51→        durations: Vec<f64>,
    52→    ) -> Result<Self, ValidationError> {
    53→        let name = name.into();
    54→        let onsets = validate_onsets(onsets)?;
    55→        let durations = validate_durations(durations, onsets.len())?;
    56→        
    57→        // Validate dimensions
    58→        if values.nrows() != onsets.len() {
    59→            return Err(ValidationError::LengthMismatch {
    60→                expected: onsets.len(),
    61→                actual: values.nrows(),
    62→            });
    63→        }
    64→        
    65→        // Check for finite values
    66→        if values.iter().any(|&x| !x.is_finite()) {
    67→            return Err(ValidationError::NonFiniteValues);
    68→        }
    69→        
    70→        // Generate default column names
    71→        let n_columns = values.ncols();
    72→        let column_names: Vec<String> = (0..n_columns)
    73→            .map(|i| format!("{}_{}", name, i + 1))
    74→            .collect();
    75→        
    76→        Ok(Self {
    77→            name,
    78→            onsets,
    79→            durations,
    80→            values,
    81→            column_names,
    82→        })
    83→    }
    84→    
    85→    /// Set custom column names.
    86→    pub fn with_column_names(mut self, names: Vec<String>) -> Result<Self, ValidationError> {
    87→        if names.len() != self.n_columns() {
    88→            return Err(ValidationError::LengthMismatch {
    89→                expected: self.n_columns(),
    90→                actual: names.len(),
    91→            });
    92→        }
    93→        self.column_names = names;
    94→        Ok(self)
    95→    }
    96→    
    97→    /// Number of columns.
    98→    pub fn n_columns(&self) -> usize {
    99→        self.values.ncols()
   100→    }
   101→    
   102→    /// Get a specific column.
   103→    pub fn get_column(&self, index: usize) -> Option<Array1<f64>> {
   104→        if index < self.n_columns() {
   105→            Some(self.values.column(index).to_owned())
   106→        } else {
   107→            None
   108→        }
   109→    }
   110→    
   111→    /// Get a column by name.
   112→    pub fn get_column_by_name(&self, name: &str) -> Option<Array1<f64>> {
   113→        self.column_names.iter()
   114→            .position(|n| n == name)
   115→            .and_then(|idx| self.get_column(idx))
   116→    }
   117→    
   118→    /// Split into separate EventVariable objects by column.
   119→    pub fn split_columns(&self) -> HashMap<String, crate::events::EventVariable> {
   120→        use crate::events::EventVariable;
   121→        
   122→        let mut result = HashMap::new();
   123→        
   124→        for (i, col_name) in self.column_names.iter().enumerate() {
   125→            let values: Vec<f64> = self.values.column(i).to_vec();
   126→            
   127→            if let Ok(event) = EventVariable::new(
   128→                col_name.clone(),
   129→                self.onsets.to_vec(),
   130→                values,
   131→                self.durations.to_vec(),
   132→            ) {
   133→                // Don't center or scale - already processed
   134→                let event = event.with_center(false).with_scale(false);
   135→                result.insert(col_name.clone(), event);
   136→            }
   137→        }
   138→        
   139→        result
   140→    }
   141→    
   142→    /// Apply transformation matrix to values.
   143→    pub fn apply_transform(&self, transform: &Array2<f64>) -> Result<Self, ValidationError> {
   144→        // Check dimensions
   145→        if transform.nrows() != self.n_columns() {
   146→            return Err(ValidationError::InvalidParameter(
   147→                format!("Transform matrix rows ({}) must match number of columns ({})",
   148→                        transform.nrows(), self.n_columns())
   149→            ));
   150→        }
   151→        
   152→        // Matrix multiply: values @ transform
   153→        let new_values = self.values.dot(transform);
   154→        
   155→        // Create new column names
   156→        let n_new_cols = transform.ncols();
   157→        let column_names: Vec<String> = (0..n_new_cols)
   158→            .map(|i| format!("{}_transformed_{}", self.name, i + 1))
   159→            .collect();
   160→        
   161→        Ok(Self {
   162→            name: format!("{}_transformed", self.name),
   163→            onsets: self.onsets.clone(),
   164→            durations: self.durations.clone(),
   165→            values: new_values,
   166→            column_names,
   167→        })
   168→    }
   169→}
   170→
   171→impl EventSpec for EventMatrix {
   172→    fn name(&self) -> &str {
   173→        &self.name
   174→    }
