pub mod dataframe_basic {
    use crate::types::ValidationError;
    use std::collections::HashMap;

    /// Simple DataFrame for event data
    #[derive(Debug, Clone)]
    pub struct DataFrame {
        /// Numeric columns
        pub columns: HashMap<String, Vec<f64>>,
        /// String columns
        pub str_columns: HashMap<String, Vec<String>>,
        /// Column order (for consistent output)
        column_order: Vec<String>,
    }

    impl DataFrame {
        /// Create new DataFrame
        pub fn new() -> Self {
            Self {
                columns: HashMap::new(),
                str_columns: HashMap::new(),
                column_order: Vec::new(),
            }
        }

        /// Add numeric column
        pub fn add_column(&mut self, name: impl Into<String>, values: Vec<f64>) -> Result<(), ValidationError> {
            let name = name.into();
            let expected_len = self.validate_length(values.len())?;
            if values.len() != expected_len {
                return Err(ValidationError::LengthMismatch {
                    expected: expected_len,
                    actual: values.len(),
                });
            }

            if !self.column_order.contains(&name) {
                self.column_order.push(name.clone());
            }
            self.columns.insert(name, values);
            Ok(())
        }

        /// Add string column
        pub fn add_str_column(&mut self, name: impl Into<String>, values: Vec<String>) -> Result<(), ValidationError> {
            let name = name.into();
            let expected_len = self.validate_length(values.len())?;
            if values.len() != expected_len {
                return Err(ValidationError::LengthMismatch {
                    expected: expected_len,
                    actual: values.len(),
                });
            }

            if !self.column_order.contains(&name) {
                self.column_order.push(name.clone());
            }
            self.str_columns.insert(name, values);
            Ok(())
        }

        /// Get numeric column
        pub fn get_column(&self, name: &str) -> Option<Vec<f64>> {
            self.columns.get(name).cloned()
        }

        /// Get string column
        pub fn get_str_column(&self, name: &str) -> Option<Vec<String>> {
            self.str_columns.get(name).cloned()
        }

        /// Get column names in order
        pub fn column_names(&self) -> Vec<String> {
            self.column_order.clone()
        }

        /// Number of rows
        pub fn len(&self) -> usize {
            self.columns.values()
                .map(|v| v.len())
                .chain(self.str_columns.values().map(|v| v.len()))
                .max()
                .unwrap_or(0)
        }

        /// Check if empty
        pub fn is_empty(&self) -> bool {
            self.len() == 0
        }

        /// Validate column length consistency
        fn validate_length(&self, new_len: usize) -> Result<usize, ValidationError> {
            let current_len = self.len();
            if current_len == 0 {
                Ok(new_len)
            } else if new_len == 0 {
                Err(ValidationError::EmptyArray)
            } else {
                Ok(current_len)
            }
        }

        /// Get all string columns
        pub fn string_columns(&self) -> HashMap<String, Vec<String>> {
            self.str_columns.clone()
        }

        /// Get all numeric columns
        pub fn numeric_columns(&self) -> HashMap<String, Vec<f64>> {
            self.columns.clone()
        }

        /// Get column as strings (works for both numeric and string columns)
        pub fn get(&self, name: &str) -> Option<Vec<String>> {
            if let Some(values) = self.str_columns.get(name) {
                Some(values.clone())
            } else if let Some(values) = self.columns.get(name) {
                Some(values.iter().map(|v| v.to_string()).collect())
            } else {
                None
            }
        }

        /// Insert a column (converts strings to appropriate type)
        pub fn insert(&mut self, name: impl Into<String>, values: Vec<&str>) {
            let name = name.into();

            // Try to parse as numeric first
            let numeric_values: Result<Vec<f64>, _> = values.iter()
                .map(|s| s.parse::<f64>())
                .collect();

            if let Ok(nums) = numeric_values {
                let _ = self.add_column(name, nums);
            } else {
                // Store as strings
                let string_values: Vec<String> = values.into_iter()
                    .map(|s| s.to_string())
                    .collect();
                let _ = self.add_str_column(name, string_values);
            }
        }

        /// Iterate over all columns
        pub fn iter(&self) -> impl Iterator<Item = (String, Vec<String>)> + '_ {
            self.column_order.iter().map(move |name| {
                let values = self.get(name).unwrap_or_default();
                (name.clone(), values)
            })
        }
    }

    /// Builder for DataFrame
    pub struct DataFrameBuilder {
        df: DataFrame,
    }

    impl DataFrameBuilder {
        /// Create new builder
        pub fn new() -> Self {
            Self {
                df: DataFrame::new(),
            }
        }

        /// Add numeric column
        pub fn with_column(mut self, name: impl Into<String>, values: Vec<f64>) -> Result<Self, ValidationError> {
            self.df.add_column(name, values)?;
            Ok(self)
        }

        /// Add string column
        pub fn with_str_column(mut self, name: impl Into<String>, values: Vec<&str>) -> Result<Self, ValidationError> {
            let string_values: Vec<String> = values.into_iter().map(|s| s.to_string()).collect();
            self.df.add_str_column(name, string_values)?;
            Ok(self)
        }

        /// Build the DataFrame
        pub fn build(self) -> DataFrame {
            self.df
        }
    }

    impl Default for DataFrameBuilder {
        fn default() -> Self {
            Self::new()
        }
    }
}

