//! Core data structures for fmridesign.

use crate::types::{ValidationError, EventSpec, EventType, BasisFunction};
use crate::hrf;
use fmrihrf::{SamplingFrame, Hrf};
use ndarray::{Array1, Array2, ArrayView1, Axis};
use std::collections::HashMap;
use std::fmt;

// Import DataFrame based on feature flags - handled by pub use below

/// Main model struct that holds all events and generates design matrices.
#[derive(Debug)]
pub struct EventModel {
    /// List of events in the model
    pub events: Vec<Box<dyn EventSpec>>,
    /// Sampling frame
    pub sampling_frame: SamplingFrame,
    /// Name for the model
    pub name: String,
}

impl EventModel {
    /// Create a new EventModel.
    pub fn new(events: Vec<Box<dyn EventSpec>>, sampling_frame: SamplingFrame) -> Result<Self, ValidationError> {
        if events.is_empty() {
            return Err(ValidationError::InvalidParameter("EventModel requires at least one event".to_string()));
        }

        Ok(EventModel {
            events,
            sampling_frame,
            name: "EventModel".to_string(),
        })
    }

    /// Generate the design matrix.
    pub fn generate_design_matrix(&self) -> Result<Array2<f64>, ValidationError> {
        self.generate_design_matrix_impl(false)
    }

    /// Generate the design matrix with caching.
    pub fn generate_design_matrix_cached(&self) -> Result<Array2<f64>, ValidationError> {
        self.generate_design_matrix_impl(true)
    }

    /// Internal implementation of design matrix generation.
    fn generate_design_matrix_impl(&self, use_cache: bool) -> Result<Array2<f64>, ValidationError> {
        let mut columns = Vec::new();
        let mut column_names = Vec::new();

        // Get sampling points
        let sampling_points_vec = self.sampling_frame.samples();
        let n_samples = sampling_points_vec.len();
        let sampling_points = Array1::from_vec(sampling_points_vec);

        // Generate columns for each event
        for event in &self.events {
            let event_matrix = if use_cache {
                // Use cached computation
                self.generate_event_matrix_cached(event.as_ref(), &sampling_points)?
            } else {
                // Direct computation
                event.design_matrix(&sampling_points)?
            };

            let event_names = event.column_names();

            // Ensure correct dimensions
            if event_matrix.nrows() != n_samples {
                return Err(ValidationError::DimensionError {
                    expected: n_samples,
                    actual: event_matrix.nrows(),
                });
            }

            // Add columns
            for i in 0..event_matrix.ncols() {
                columns.push(event_matrix.column(i).to_owned());
                column_names.push(event_names.get(i).cloned().unwrap_or_else(|| format!("col_{}", i)));
            }
        }

        // Combine all columns into design matrix
        if columns.is_empty() {
            return Ok(Array2::zeros((n_samples, 0)));
        }

        let n_cols = columns.len();
        let mut design_matrix = Array2::zeros((n_samples, n_cols));

        for (i, col) in columns.into_iter().enumerate() {
            design_matrix.column_mut(i).assign(&col);
        }

        Ok(design_matrix)
    }

    /// Get column names for the design matrix.
    pub fn column_names(&self) -> Vec<String> {
        let mut names = Vec::new();
        for event in &self.events {
            names.extend(event.column_names());
        }
        names
    }

    /// Get the number of columns in the design matrix.
    pub fn n_columns(&self) -> usize {
        self.events.iter().map(|e| e.n_columns().unwrap_or(1)).sum()
    }

    /// Get the number of samples.
    pub fn n_samples(&self) -> usize {
        self.sampling_frame.n_scans()
    }

    /// Get a reference to the events.
    pub fn events(&self) -> &[Box<dyn EventSpec>] {
        &self.events
    }

    /// Get the number of events.
    pub fn n_events(&self) -> usize {
        self.events.len()
    }

    /// Add an event to the model.
    pub fn add_event(&mut self, event: Box<dyn EventSpec>) {
        self.events.push(event);
    }

    /// Set the model name.
    pub fn with_name(mut self, name: impl Into<String>) -> Self {
        self.name = name.into();
        self
    }

    /// Generate event matrix with caching.
    fn generate_event_matrix_cached(
        &self,
        event: &dyn EventSpec,
        sampling_points: &Array1<f64>,
    ) -> Result<Array2<f64>, ValidationError> {
        use crate::cache::{cached_design_matrix, hash_array};
        use std::collections::hash_map::DefaultHasher;
        use std::hash::{Hash, Hasher};

        // Create a hash of event parameters
        let mut hasher = DefaultHasher::new();
        event.name().hash(&mut hasher);
        event.event_type().hash(&mut hasher);
        event.n_events().hash(&mut hasher);

        // Hash event-specific data
        for &onset in event.onsets().iter() {
            ((onset * 1000.0) as i64).hash(&mut hasher);
        }
        for &duration in event.durations().iter() {
            ((duration * 1000.0) as i64).hash(&mut hasher);
        }

        let event_params_hash = hasher.finish();

        // Use cached computation
        cached_design_matrix(
            event.name(),
            sampling_points,
            event_params_hash,
            || event.design_matrix(sampling_points),
        )
    }

    /// Get column indices for each event/term.
    /// Returns a vector of (event_name, column_indices) tuples.
    pub fn column_indices(&self) -> Result<Vec<(String, Vec<usize>)>, ValidationError> {
        let mut result = Vec::new();
        let mut current_idx = 0;

        for event in &self.events {
            let n_cols = event.n_columns().unwrap_or(1);
            let indices: Vec<usize> = (current_idx..current_idx + n_cols).collect();
            result.push((event.name().to_string(), indices));
            current_idx += n_cols;
        }

        Ok(result)
    }
}

impl fmt::Display for EventModel {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        writeln!(f, "EventModel '{}' with {} events:", self.name, self.events.len())?;
        for (i, event) in self.events.iter().enumerate() {
            writeln!(f, "  {}: {} ({:?})", i, event.name(), event.event_type())?;
        }
        writeln!(f, "Sampling: {} samples", self.n_samples())?;
        writeln!(f, "Design matrix: {} x {}", self.n_samples(), self.n_columns())?;
        Ok(())
    }
}

/// An event that can contribute columns to a design matrix.
#[derive(Debug)]
pub struct Event {
    /// Event name
    pub name: String,
    /// Event onsets
    pub onsets: Array1<f64>,
    /// Event durations (optional, defaults to 0)
    pub durations: Option<Array1<f64>>,
    /// Event amplitudes (optional, defaults to 1)
    pub amplitudes: Option<Array1<f64>>,
    /// HRF for convolution (optional)
    pub hrf: Option<Box<dyn Hrf>>,
    /// Basis function for continuous events (optional)
    pub basis: Option<Box<dyn BasisFunction>>,
}

impl Event {
    /// Create a new event.
    pub fn new(name: impl Into<String>, onsets: Vec<f64>) -> Self {
        Event {
            name: name.into(),
            onsets: Array1::from_vec(onsets),
            durations: None,
            amplitudes: None,
            hrf: None,
            basis: None,
        }
    }

    /// Set durations.
    pub fn with_durations(mut self, durations: Vec<f64>) -> Result<Self, ValidationError> {
        if durations.len() != self.onsets.len() {
            return Err(ValidationError::LengthMismatch {
                expected: self.onsets.len(),
                actual: durations.len(),
            });
        }
        self.durations = Some(Array1::from_vec(durations));
        Ok(self)
    }

    /// Set amplitudes.
    pub fn with_amplitudes(mut self, amplitudes: Vec<f64>) -> Result<Self, ValidationError> {
        if amplitudes.len() != self.onsets.len() {
            return Err(ValidationError::LengthMismatch {
                expected: self.onsets.len(),
                actual: amplitudes.len(),
            });
        }
        self.amplitudes = Some(Array1::from_vec(amplitudes));
        Ok(self)
    }

    /// Set HRF for convolution.
    pub fn with_hrf(mut self, hrf: Box<dyn Hrf>) -> Self {
        self.hrf = Some(hrf);
        self
    }

    /// Set basis function for continuous values.
    pub fn with_basis(mut self, basis: Box<dyn BasisFunction>) -> Self {
        self.basis = Some(basis);
        self
    }
}

impl EventSpec for Event {
    fn name(&self) -> &str {
        &self.name
    }

    fn event_type(&self) -> EventType {
        EventType::Continuous
    }

    fn design_matrix(&self, sampling_points: &Array1<f64>) -> Result<Array2<f64>, ValidationError> {
        let n_samples = sampling_points.len();
        let durations = self.durations.as_ref();
        let amplitudes = self.amplitudes.as_ref();

        // Create base regressor (before any transformations)
        let mut regressor = Array1::zeros(n_samples);
        let tr = 2.0; // Default TR, should be provided differently

        for (i, &onset) in self.onsets.iter().enumerate() {
            let duration = durations.as_ref().and_then(|d| d.get(i)).copied().unwrap_or(0.0);
            let amplitude = amplitudes.as_ref().and_then(|a| a.get(i)).copied().unwrap_or(1.0);

            // Find samples that overlap with this event
            for (j, &t) in sampling_points.iter().enumerate() {
                // Check if this sample overlaps with the event
                // Using the same logic as the original implementation
                let sample_start = t - tr / 2.0;
                let sample_end = t + tr / 2.0;

                if sample_end > onset && sample_start < onset + duration {
                    regressor[j] += amplitude;
                }
            }
        }

        // Apply HRF convolution if specified
        let convolved = if let Some(hrf) = &self.hrf {
            // Simple discrete convolution
            let hrf_samples = Array1::linspace(0.0, 30.0, 301);
            let hrf_values = hrf.evaluate(&hrf_samples)
                .map_err(|e| ValidationError::InvalidParameter(format!("HRF evaluation failed: {}", e)))?;

            // For now, use the first column if HRF returns multiple
            let hrf_vec = hrf_values.column(0);

            // Convolve using discrete convolution
            let precision = 0.1; // Default precision
            convolve_discrete(&regressor.view(), &hrf_vec.view(), precision, tr)
        } else {
            regressor
        };

        // Apply basis function if specified
        let final_matrix = if let Some(basis) = &self.basis {
            // Apply basis function to the convolved regressor
            let basis_matrix = basis.evaluate(&convolved.view())?;
            basis_matrix
        } else {
            // Return as single column matrix
            convolved.insert_axis(Axis(1))
        };

        Ok(final_matrix)
    }

    fn onsets(&self) -> &Array1<f64> {
        &self.onsets
    }

    fn durations(&self) -> &Array1<f64> {
        // Return empty array if no durations
        self.durations.as_ref().unwrap_or(&self.onsets)
    }

    fn n_columns(&self) -> Option<usize> {
        Some(self.basis.as_ref().map(|b| b.nbasis()).unwrap_or(1))
    }

    fn to_dataframe(&self) -> crate::core::DataFrame {
        let mut df = DataFrame::new();
        let _ = df.add_column("onset", self.onsets.to_vec());
        if let Some(durations) = &self.durations {
            let _ = df.add_column("duration", durations.to_vec());
        }
        if let Some(amplitudes) = &self.amplitudes {
            let _ = df.add_column("amplitude", amplitudes.to_vec());
        }
        df
    }

    fn column_names(&self) -> Vec<String> {
        if let Some(basis) = &self.basis {
            (0..basis.nbasis()).map(|i| format!("{}_{}", self.name, i + 1)).collect()
        } else {
            vec![self.name.clone()]
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }

    fn clone_box(&self) -> Box<dyn EventSpec> {
        // Create a new event with cloned data
        let mut event = Event::new(self.name.clone(), self.onsets.to_vec());

        if let Some(ref durations) = self.durations {
            event.durations = Some(durations.clone());
        }

        if let Some(ref amplitudes) = self.amplitudes {
            event.amplitudes = Some(amplitudes.clone());
        }

        // Note: HRF and basis functions can't be cloned easily
        // They would need to be recreated when needed

        Box::new(event)
    }

    fn filter(&self, mask: &[bool]) -> Result<Box<dyn EventSpec>, ValidationError> {
        if mask.len() != self.onsets.len() {
            return Err(ValidationError::LengthMismatch {
                expected: self.onsets.len(),
                actual: mask.len(),
            });
        }

        let mut filtered_onsets = Vec::new();
        let mut filtered_durations = Vec::new();
        let mut filtered_amplitudes = Vec::new();

        for (i, &include) in mask.iter().enumerate() {
            if include {
                filtered_onsets.push(self.onsets[i]);
                if let Some(ref durations) = self.durations {
                    filtered_durations.push(durations[i]);
                }
                if let Some(ref amplitudes) = self.amplitudes {
                    filtered_amplitudes.push(amplitudes[i]);
                }
            }
        }

        if filtered_onsets.is_empty() {
            return Err(ValidationError::InvalidParameter(
                "Filter resulted in empty event".to_string()
            ));
        }

        let mut event = Event::new(self.name.clone(), filtered_onsets);

        if !filtered_durations.is_empty() && self.durations.is_some() {
            event = event.with_durations(filtered_durations)?;
        }

        if !filtered_amplitudes.is_empty() && self.amplitudes.is_some() {
            event = event.with_amplitudes(filtered_amplitudes)?;
        }

        // Note: basis functions can't be easily cloned

        Ok(Box::new(event))
    }
}

/// Simple discrete convolution function
fn convolve_discrete(signal: &ArrayView1<f64>, kernel: &ArrayView1<f64>, precision: f64, _tr: f64) -> Array1<f64> {
    let signal_len = signal.len();
    let kernel_len = kernel.len();

    let mut result = Array1::zeros(signal_len);

    for i in 0..signal_len {
        let mut sum = 0.0;
        for j in 0..kernel_len.min(i + 1) {
            if i >= j {
                sum += signal[i - j] * kernel[j] * precision;
            }
        }
        result[i] = sum;
    }

    result
}

/// Build event models using a fluent interface.
pub struct EventModelBuilder {
    events: Vec<Box<dyn EventSpec>>,
    sampling_frame: Option<SamplingFrame>,
    name: Option<String>,
}

impl EventModelBuilder {
    /// Create a new builder.
    pub fn new() -> Self {
        EventModelBuilder {
            events: Vec::new(),
            sampling_frame: None,
            name: None,
        }
    }

    /// Add an event.
    pub fn add_event(mut self, event: Box<dyn EventSpec>) -> Self {
        self.events.push(event);
        self
    }

    /// Set the sampling frame.
    pub fn sampling_frame(mut self, sf: SamplingFrame) -> Self {
        self.sampling_frame = Some(sf);
        self
    }

    /// Set the model name.
    pub fn name(mut self, name: impl Into<String>) -> Self {
        self.name = Some(name.into());
        self
    }

    /// Build the model.
    pub fn build(self) -> Result<EventModel, ValidationError> {
        let sampling_frame = self.sampling_frame.ok_or_else(|| {
            ValidationError::InvalidParameter("Sampling frame is required".to_string())
        })?;

        let mut model = EventModel::new(self.events, sampling_frame)?;

        if let Some(name) = self.name {
            model.name = name;
        }

        Ok(model)
    }
}

impl Default for EventModelBuilder {
    fn default() -> Self {
        Self::new()
    }
}

/// Baseline model for drift correction.
#[derive(Debug)]
pub struct BaselineModel {
    /// Basis function for the baseline
    pub basis: Box<dyn BasisFunction>,
    /// Model name
    pub name: String,
}

impl BaselineModel {
    /// Create a new baseline model.
    pub fn new(basis: Box<dyn BasisFunction>) -> Self {
        let name = format!("Baseline[{}]", basis.name());
        BaselineModel { basis, name }
    }

    /// Create polynomial baseline model.
    pub fn polynomial(degree: usize) -> Self {
        use crate::basis::PolynomialBasis;
        let basis = Box::new(PolynomialBasis::new(degree).with_intercept(true));
        Self::new(basis)
    }

    /// Create spline baseline model.
    pub fn spline(df: usize) -> Self {
        use crate::basis::BSplineBasis;
        let basis = Box::new(BSplineBasis::new(df));
        Self::new(basis)
    }

    /// Generate baseline design matrix.
    pub fn design_matrix(&self, sampling_frame: &SamplingFrame) -> Result<Array2<f64>, ValidationError> {
        let samples = sampling_frame.samples();
        let n_samples = samples.len();

        // Create time vector normalized to [0, 1]
        let duration = if samples.is_empty() {
            1.0
        } else {
            samples[samples.len() - 1] - samples[0]
        };
        let normalized_time = Array1::from_vec(
            samples.iter()
                .map(|&t| (t - samples[0]) / duration)
                .collect()
        );

        // Apply basis function
        self.basis.evaluate(&normalized_time.view())
    }

    /// Get column names.
    pub fn column_names(&self) -> Vec<String> {
        (0..self.basis.nbasis())
            .map(|i| format!("{}_{}", self.name, i + 1))
            .collect()
    }
}

impl fmt::Display for BaselineModel {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{} with {} basis functions", self.name, self.basis.nbasis())
    }
}

/// Combined model with events and baseline.
#[derive(Debug)]
pub struct DesignMatrix {
    /// Event model
    pub event_model: EventModel,
    /// Baseline model (optional)
    pub baseline_model: Option<BaselineModel>,
    /// Cached design matrix
    cached_matrix: Option<Array2<f64>>,
    /// Cached column names
    cached_names: Option<Vec<String>>,
}

impl DesignMatrix {
    /// Create from event model.
    pub fn from_event_model(event_model: EventModel) -> Self {
        DesignMatrix {
            event_model,
            baseline_model: None,
            cached_matrix: None,
            cached_names: None,
        }
    }

    /// Add baseline model.
    pub fn with_baseline(mut self, baseline: BaselineModel) -> Self {
        self.baseline_model = Some(baseline);
        self.cached_matrix = None;
        self.cached_names = None;
        self
    }

    /// Get the full design matrix.
    pub fn matrix(&mut self) -> Result<&Array2<f64>, ValidationError> {
        if self.cached_matrix.is_none() {
            self.generate_matrix()?;
        }
        Ok(self.cached_matrix.as_ref().unwrap())
    }

    /// Get column names.
    pub fn column_names(&mut self) -> Result<&Vec<String>, ValidationError> {
        if self.cached_names.is_none() {
            self.generate_matrix()?;
        }
        Ok(self.cached_names.as_ref().unwrap())
    }

    /// Generate the combined matrix.
    fn generate_matrix(&mut self) -> Result<(), ValidationError> {
        let event_matrix = self.event_model.generate_design_matrix()?;
        let mut column_names = self.event_model.column_names();

        let combined_matrix = if let Some(baseline) = &self.baseline_model {
            let baseline_matrix = baseline.design_matrix(&self.event_model.sampling_frame)?;
            let baseline_names = baseline.column_names();

            // Ensure same number of rows
            if event_matrix.nrows() != baseline_matrix.nrows() {
                return Err(ValidationError::DimensionError {
                    expected: event_matrix.nrows(),
                    actual: baseline_matrix.nrows(),
                });
            }

            // Concatenate matrices
            let n_rows = event_matrix.nrows();
            let n_event_cols = event_matrix.ncols();
            let n_baseline_cols = baseline_matrix.ncols();
            let n_total_cols = n_event_cols + n_baseline_cols;

            let mut combined = Array2::zeros((n_rows, n_total_cols));

            // Copy event columns
            for i in 0..n_event_cols {
                combined.column_mut(i).assign(&event_matrix.column(i));
            }

            // Copy baseline columns
            for i in 0..n_baseline_cols {
                combined.column_mut(n_event_cols + i).assign(&baseline_matrix.column(i));
            }

            column_names.extend(baseline_names);
            combined
        } else {
            event_matrix
        };

        self.cached_matrix = Some(combined_matrix);
        self.cached_names = Some(column_names);

        Ok(())
    }
}

impl fmt::Display for DesignMatrix {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "DesignMatrix with {} events", self.event_model.n_events())?;
        if self.baseline_model.is_some() {
            write!(f, " and baseline model")?;
        }

        if let (Some(matrix), Some(names)) = (&self.cached_matrix, &self.cached_names) {
            write!(f, "\nShape: {} x {}", matrix.nrows(), matrix.ncols())?;
            write!(f, "\nColumns: {}", names.join(", "))?;
        } else {
            let n_cols = self.event_model.n_columns() + 
                self.baseline_model.as_ref().map(|b| b.basis.nbasis()).unwrap_or(0);
            write!(
                f,
                "\nExpected shape: {} x {}",
                self.event_model.n_samples(),
                n_cols
            )?;
        }

        Ok(())
    }
}

/// Factory function to create events from different specifications.
pub fn create_event(
    name: impl Into<String>,
    onsets: Vec<f64>,
    event_type: &str,
    options: HashMap<String, String>,
) -> Result<Box<dyn EventSpec>, ValidationError> {
    let name = name.into();

    match event_type {
        "simple" | "event" => {
            let mut event = Event::new(name, onsets);

            // Add durations if specified
            if let Some(dur_str) = options.get("durations") {
                let durations: Result<Vec<f64>, _> = dur_str
                    .split(',')
                    .map(|s| s.trim().parse())
                    .collect();
                event = event.with_durations(durations.map_err(|_| {
                    ValidationError::InvalidParameter("Invalid durations format".to_string())
                })?)?;
            }

            // Add amplitudes if specified
            if let Some(amp_str) = options.get("amplitudes") {
                let amplitudes: Result<Vec<f64>, _> = amp_str
                    .split(',')
                    .map(|s| s.trim().parse())
                    .collect();
                event = event.with_amplitudes(amplitudes.map_err(|_| {
                    ValidationError::InvalidParameter("Invalid amplitudes format".to_string())
                })?)?;
            }

            // Add HRF if specified
            if let Some(hrf_name) = options.get("hrf") {
                let hrf = hrf::create_hrf_by_name(hrf_name)
                    .ok_or_else(|| ValidationError::InvalidParameter(format!("Unknown HRF: {}", hrf_name)))?;
                event = event.with_hrf(hrf);
            }

            // Add basis if specified
            if let Some(basis_type) = options.get("basis") {
                use crate::basis::{PolynomialBasis, BSplineBasis};

                let basis: Box<dyn crate::types::BasisFunction> = match basis_type.as_str() {
                    "polynomial" => {
                        let degree = options.get("degree")
                            .and_then(|s| s.parse().ok())
                            .unwrap_or(3);
                        Box::new(PolynomialBasis::new(degree))
                    }
                    "spline" | "bspline" => {
                        let df = options.get("df")
                            .and_then(|s| s.parse().ok())
                            .unwrap_or(4);
                        Box::new(BSplineBasis::new(df))
                    }
                    _ => return Err(ValidationError::InvalidParameter(
                        format!("Unknown basis type: {}", basis_type)
                    ))
                };
                event = event.with_basis(basis);
            }

            Ok(Box::new(event))
        }
        "factor" | "categorical" => {
            // For categorical events, we need values
            let values_str = options.get("values")
                .ok_or_else(|| ValidationError::InvalidParameter(
                    "Categorical events require 'values' parameter".to_string()
                ))?;

            let values: Vec<String> = values_str
                .split(',')
                .map(|s| s.trim().to_string())
                .collect();

            if values.len() != onsets.len() {
                return Err(ValidationError::LengthMismatch {
                    expected: onsets.len(),
                    actual: values.len(),
                });
            }

            // Create EventFactor
            use crate::events::EventFactor;

            // Get durations if specified, otherwise use zeros
            let durations = if let Some(dur_str) = options.get("durations") {
                let durations: Result<Vec<f64>, _> = dur_str
                    .split(',')
                    .map(|s| s.trim().parse())
                    .collect();
                durations.map_err(|_| {
                    ValidationError::InvalidParameter("Invalid durations format".to_string())
                })?
            } else {
                vec![0.0; onsets.len()]
            };

            let values_refs: Vec<&str> = values.iter().map(|s| s.as_str()).collect();
            let factor = EventFactor::new(name, onsets, values_refs, durations)?;
            Ok(Box::new(factor))
        }
        "variable" | "continuous" => {
            // For continuous events, we need values
            let values_str = options.get("values")
                .ok_or_else(|| ValidationError::InvalidParameter(
                    "Continuous events require 'values' parameter".to_string()
                ))?;

            let values: Result<Vec<f64>, _> = values_str
                .split(',')
                .map(|s| s.trim().parse())
                .collect();

            let values = values.map_err(|_| {
                ValidationError::InvalidParameter("Invalid values format".to_string())
            })?;

            if values.len() != onsets.len() {
                return Err(ValidationError::LengthMismatch {
                    expected: onsets.len(),
                    actual: values.len(),
                });
            }

            // Get durations if specified, otherwise use zeros
            let durations = if let Some(dur_str) = options.get("durations") {
                let durations: Result<Vec<f64>, _> = dur_str
                    .split(',')
                    .map(|s| s.trim().parse())
                    .collect();
                durations.map_err(|_| {
                    ValidationError::InvalidParameter("Invalid durations format".to_string())
                })?
            } else {
                vec![0.0; onsets.len()]
            };

            // Create EventVariable
            use crate::events::EventVariable;

            let variable = EventVariable::new(name, onsets, values, durations)?;
            Ok(Box::new(variable))
        }
        _ => Err(ValidationError::InvalidParameter(
            format!("Unknown event type: {}", event_type)
        ))
    }
}

// DataFrame implementation
pub use crate::dataframe_polars::{DataFrame, DataFrameBuilder};

#[cfg(not(feature = "dataframe"))]
pub mod dataframe_basic {
    use crate::types::ValidationError;
    use std::collections::HashMap;

    /// Simple DataFrame for event data
    #[derive(Debug, Clone)]
    pub struct DataFrame {
        /// Numeric columns
        pub columns: HashMap<String, Vec<f64>>,
        /// String columns
        pub str_columns: HashMap<String, Vec<String>>,
        /// Column order (for consistent output)
        column_order: Vec<String>,
    }

    impl DataFrame {
        /// Create new DataFrame
        pub fn new() -> Self {
            Self {
                columns: HashMap::new(),
                str_columns: HashMap::new(),
                column_order: Vec::new(),
            }
        }

        /// Add numeric column
        pub fn add_column(&mut self, name: impl Into<String>, values: Vec<f64>) -> Result<(), ValidationError> {
            let name = name.into();
            let expected_len = self.validate_length(values.len())?;
            if values.len() != expected_len {
                return Err(ValidationError::LengthMismatch {
                    expected: expected_len,
                    actual: values.len(),
                });
            }

            if !self.column_order.contains(&name) {
                self.column_order.push(name.clone());
            }
            self.columns.insert(name, values);
            Ok(())
        }

        /// Add string column
        pub fn add_str_column(&mut self, name: impl Into<String>, values: Vec<String>) -> Result<(), ValidationError> {
            let name = name.into();
            let expected_len = self.validate_length(values.len())?;
            if values.len() != expected_len {
                return Err(ValidationError::LengthMismatch {
                    expected: expected_len,
                    actual: values.len(),
                });
            }

            if !self.column_order.contains(&name) {
                self.column_order.push(name.clone());
            }
            self.str_columns.insert(name, values);
            Ok(())
        }

        /// Get numeric column
        pub fn get_column(&self, name: &str) -> Option<Vec<f64>> {
            self.columns.get(name).cloned()
        }

        /// Get string column
        pub fn get_str_column(&self, name: &str) -> Option<Vec<String>> {
            self.str_columns.get(name).cloned()
        }

        /// Get column names in order
        pub fn column_names(&self) -> Vec<String> {
            self.column_order.clone()
        }

        /// Number of rows
        pub fn len(&self) -> usize {
            self.columns.values()
                .map(|v| v.len())
                .chain(self.str_columns.values().map(|v| v.len()))
                .max()
                .unwrap_or(0)
        }

        /// Check if empty
        pub fn is_empty(&self) -> bool {
            self.len() == 0
        }

        /// Validate column length consistency
        fn validate_length(&self, new_len: usize) -> Result<usize, ValidationError> {
            let current_len = self.len();
            if current_len == 0 {
                Ok(new_len)
            } else if new_len == 0 {
                Err(ValidationError::EmptyArray)
            } else {
                Ok(current_len)
            }
        }

        /// Get all string columns
        pub fn string_columns(&self) -> HashMap<String, Vec<String>> {
            self.str_columns.clone()
        }

        /// Get all numeric columns
        pub fn numeric_columns(&self) -> HashMap<String, Vec<f64>> {
            self.columns.clone()
        }

        /// Get column as strings (works for both numeric and string columns)
        pub fn get(&self, name: &str) -> Option<Vec<String>> {
            if let Some(values) = self.str_columns.get(name) {
                Some(values.clone())
            } else if let Some(values) = self.columns.get(name) {
                Some(values.iter().map(|v| v.to_string()).collect())
            } else {
                None
            }
        }

        /// Insert a column (converts strings to appropriate type)
        pub fn insert(&mut self, name: impl Into<String>, values: Vec<&str>) {
            let name = name.into();

            // Try to parse as numeric first
            let numeric_values: Result<Vec<f64>, _> = values.iter()
                .map(|s| s.parse::<f64>())
                .collect();

            if let Ok(nums) = numeric_values {
                let _ = self.add_column(name, nums);
            } else {
                // Store as strings
                let string_values: Vec<String> = values.into_iter()
                    .map(|s| s.to_string())
                    .collect();
                let _ = self.add_str_column(name, string_values);
            }
        }

        /// Iterate over all columns
        pub fn iter(&self) -> impl Iterator<Item = (String, Vec<String>)> + '_ {
            self.column_order.iter().map(move |name| {
                let values = self.get(name).unwrap_or_default();
                (name.clone(), values)
            })
        }

        /// Get unique values in a column
        pub fn unique(&self, column: &str) -> Result<Vec<String>, ValidationError> {
            let values = self.get(column)
                .ok_or_else(|| ValidationError::MissingColumn(column.to_string()))?;

            let mut unique_values: Vec<String> = values.into_iter()
                .collect::<std::collections::HashSet<_>>()
                .into_iter()
                .collect();
            unique_values.sort();

            Ok(unique_values)
        }

        /// Select columns
        pub fn select<I, S>(&self, columns: I) -> Result<DataFrame, ValidationError>
        where
            I: IntoIterator<Item = S>,
            S: AsRef<str>,
        {
            let mut new_df = DataFrame::new();

            for col_name in columns {
                let col_name = col_name.as_ref();

                if let Some(values) = self.columns.get(col_name) {
                    new_df.add_column(col_name, values.clone())?;
                } else if let Some(values) = self.str_columns.get(col_name) {
                    new_df.add_str_column(col_name, values.clone())?;
                } else {
                    return Err(ValidationError::MissingColumn(col_name.to_string()));
                }
            }

            Ok(new_df)
        }

        /// Filter rows based on a condition
        pub fn filter(&self, mask: &[bool]) -> Result<DataFrame, ValidationError> {
            if mask.len() != self.len() {
                return Err(ValidationError::LengthMismatch {
                    expected: self.len(),
                    actual: mask.len(),
                });
            }

            let mut new_df = DataFrame::new();

            for name in &self.column_order {
                if let Some(values) = self.columns.get(name) {
                    let filtered: Vec<f64> = values.iter()
                        .zip(mask.iter())
                        .filter_map(|(v, &keep)| if keep { Some(*v) } else { None })
                        .collect();
                    new_df.add_column(name, filtered)?;
                } else if let Some(values) = self.str_columns.get(name) {
                    let filtered: Vec<String> = values.iter()
                        .zip(mask.iter())
                        .filter_map(|(v, &keep)| if keep { Some(v.clone()) } else { None })
                        .collect();
                    new_df.add_str_column(name, filtered)?;
                }
            }

            Ok(new_df)
        }

        /// Create from a HashMap (for compatibility)
        pub fn from_hashmap(
            columns: HashMap<String, Vec<f64>>,
            str_columns: HashMap<String, Vec<String>>,
        ) -> Result<Self, ValidationError> {
            let mut df = DataFrame::new();

            for (name, values) in columns {
                df.add_column(name, values)?;
            }

            for (name, values) in str_columns {
                df.add_str_column(name, values)?;
            }

            Ok(df)
        }
    }

    impl Default for DataFrame {
        fn default() -> Self {
            Self::new()
        }
    }

    /// Builder for DataFrame
    pub struct DataFrameBuilder {
        df: DataFrame,
    }

    impl DataFrameBuilder {
        /// Create new builder
        pub fn new() -> Self {
            Self {
                df: DataFrame::new(),
            }
        }

        /// Add numeric column
        pub fn with_column(mut self, name: impl Into<String>, values: Vec<f64>) -> Result<Self, ValidationError> {
            self.df.add_column(name, values)?;
            Ok(self)
        }

        /// Add string column
        pub fn with_str_column(mut self, name: impl Into<String>, values: Vec<&str>) -> Result<Self, ValidationError> {
            let string_values: Vec<String> = values.into_iter().map(|s| s.to_string()).collect();
            self.df.add_str_column(name, string_values)?;
            Ok(self)
        }

        /// Build the DataFrame
        pub fn build(self) -> DataFrame {
            self.df
        }
    }

    impl Default for DataFrameBuilder {
        fn default() -> Self {
            Self::new()
        }
    }
}


/// Create an event table from multiple events.
///
/// Combines multiple events into a single DataFrame for easy inspection
/// and manipulation.
///
/// # Arguments
/// * `events` - Vector of event specifications
///
/// # Returns
/// A DataFrame with columns for event name, onset, duration, and event-specific values
///
/// # Example
/// ```ignore
/// let events = vec![
///     Box::new(Event::new("cue", vec![1.0, 3.0, 5.0])),
///     Box::new(EventVariable::new("rating", vec![2.0, 4.0], vec![7.5, 3.2], vec![1.0, 1.0])?),
/// ];
/// let table = event_table(events)?;
/// ```
pub fn event_table(events: Vec<Box<dyn EventSpec>>) -> Result<DataFrame, ValidationError> {
    let mut df = DataFrame::new();
    let mut all_onsets = Vec::new();
    let mut all_durations = Vec::new();
    let mut all_event_names = Vec::new();
    let mut all_event_types = Vec::new();

    // Collect data from all events
    for event in &events {
        let n_events = event.n_events();
        let onsets = event.onsets();
        let durations = event.durations();

        // Add to combined vectors
        all_onsets.extend(onsets.iter().cloned());
        all_durations.extend(durations.iter().cloned());
        all_event_names.extend(vec![event.name().to_string(); n_events]);
        all_event_types.extend(vec![format!("{:?}", event.event_type()); n_events]);

        // Handle event-specific data
        if let Some(levels) = event.levels() {
            // For categorical events, add level information
            if let Some(values) = event.values() {
                // We'll need to track these separately and merge later
            }
        }
    }

    // Sort by onset time first
    let mut indices: Vec<usize> = (0..all_onsets.len()).collect();
    indices.sort_by(|&a, &b| {
        all_onsets[a].partial_cmp(&all_onsets[b]).unwrap()
    });

    // Create sorted data
    let sorted_onsets: Vec<f64> = indices.iter().map(|&i| all_onsets[i]).collect();
    let sorted_durations: Vec<f64> = indices.iter().map(|&i| all_durations[i]).collect();
    let sorted_names: Vec<String> = indices.iter().map(|&i| all_event_names[i].clone()).collect();
    let sorted_types: Vec<String> = indices.iter().map(|&i| all_event_types[i].clone()).collect();

    // Build the DataFrame with sorted data
    df.add_column("event", sorted_names.iter().map(|s| s.parse().unwrap_or(0.0)).collect())?;
    df.add_column("onset", sorted_onsets)?;
    df.add_column("duration", sorted_durations)?;
    df.add_str_column("event_name", sorted_names)?;
    df.add_str_column("event_type", sorted_types)?;

    Ok(df)
}

