    12→/// Main model struct that holds all events and generates design matrices.
    13→#[derive(Debug)]
    14→pub struct EventModel {
    15→    /// List of events in the model
    16→    pub events: Vec<Box<dyn EventSpec>>,
    17→    /// Sampling frame
    18→    pub sampling_frame: SamplingFrame,
    19→    /// Name for the model
