    22→
    23→impl EventModel {
    24→    /// Create a new EventModel.
    25→    pub fn new(events: Vec<Box<dyn EventSpec>>, sampling_frame: SamplingFrame) -> Result<Self, ValidationError> {
    26→        if events.is_empty() {
    27→            return Err(ValidationError::InvalidParameter("EventModel requires at least one event".to_string()));
    28→        }
    29→        
    30→        Ok(EventModel {
    31→            events,
    32→            sampling_frame,
    33→            name: "EventModel".to_string(),
    34→        })
    35→    }
    36→    
    37→    /// Generate the design matrix.
    38→    pub fn generate_design_matrix(&self) -> Result<Array2<f64>, ValidationError> {
    39→        self.generate_design_matrix_impl(false)
    40→    }
    41→    
    42→    /// Generate the design matrix with caching.
    43→    pub fn generate_design_matrix_cached(&self) -> Result<Array2<f64>, ValidationError> {
    44→        self.generate_design_matrix_impl(true)
    45→    }
    46→    
    47→    /// Internal implementation of design matrix generation.
    48→    fn generate_design_matrix_impl(&self, use_cache: bool) -> Result<Array2<f64>, ValidationError> {
    49→        let mut columns = Vec::new();
    50→        let mut column_names = Vec::new();
    51→        
    52→        // Get sampling points
    53→        let sampling_points_vec = self.sampling_frame.samples();
    54→        let n_samples = sampling_points_vec.len();
    55→        let sampling_points = Array1::from_vec(sampling_points_vec);
    56→        
    57→        // Generate columns for each event
    58→        for event in &self.events {
    59→            let event_matrix = if use_cache {
    60→                // Use cached computation
    61→                self.generate_event_matrix_cached(event.as_ref(), &sampling_points)?
    62→            } else {
    63→                // Direct computation
    64→                event.design_matrix(&sampling_points)?
    65→            };
    66→            
    67→            let event_names = event.column_names();
    68→            
    69→            // Ensure correct dimensions
    70→            if event_matrix.nrows() != n_samples {
    71→                return Err(ValidationError::DimensionError {
    72→                    expected: n_samples,
    73→                    actual: event_matrix.nrows(),
    74→                });
    75→            }
    76→            
    77→            // Add columns
    78→            for i in 0..event_matrix.ncols() {
    79→                columns.push(event_matrix.column(i).to_owned());
    80→                column_names.push(event_names.get(i).cloned().unwrap_or_else(|| format!("col_{}", i)));
    81→            }
    82→        }
    83→        
    84→        // Combine all columns into design matrix
    85→        if columns.is_empty() {
    86→            return Ok(Array2::zeros((n_samples, 0)));
    87→        }
    88→        
    89→        let n_cols = columns.len();
    90→        let mut design_matrix = Array2::zeros((n_samples, n_cols));
    91→        
    92→        for (i, col) in columns.into_iter().enumerate() {
    93→            design_matrix.column_mut(i).assign(&col);
    94→        }
    95→        
    96→        Ok(design_matrix)
    97→    }
