   121→    }
   122→    
   123→    /// Get the number of events.
   124→    pub fn n_events(&self) -> usize {
   125→        self.events.len()
   126→    }
   127→    
   128→    /// Add an event to the model.
   129→    pub fn add_event(&mut self, event: Box<dyn EventSpec>) {
