   138→    
   139→    /// Generate event matrix with caching.
   140→    fn generate_event_matrix_cached(
   141→        &self,
   142→        event: &dyn EventSpec,
   143→        sampling_points: &Array1<f64>,
   144→    ) -> Result<Array2<f64>, ValidationError> {
   145→        use crate::cache::{cached_design_matrix, hash_array};
   146→        use std::collections::hash_map::DefaultHasher;
   147→        use std::hash::{Hash, Hasher};
   148→        
   149→        // Create a hash of event parameters
   150→        let mut hasher = DefaultHasher::new();
   151→        event.name().hash(&mut hasher);
   152→        event.event_type().hash(&mut hasher);
   153→        event.n_events().hash(&mut hasher);
   154→        
   155→        // Hash event-specific data
   156→        for &onset in event.onsets().iter() {
   157→            ((onset * 1000.0) as i64).hash(&mut hasher);
   158→        }
   159→        for &duration in event.durations().iter() {
   160→            ((duration * 1000.0) as i64).hash(&mut hasher);
   161→        }
   162→        
   163→        let event_params_hash = hasher.finish();
   164→        
   165→        // Use cached computation
   166→        cached_design_matrix(
   167→            event.name(),
   168→            sampling_points,
   169→            event_params_hash,
   170→            || event.design_matrix(sampling_points),
   171→        )
   172→    }
