   352→            let _ = df.add_column("duration", durations.to_vec());
   353→        }
   354→        if let Some(amplitudes) = &self.amplitudes {
   355→            let _ = df.add_column("amplitude", amplitudes.to_vec());
   356→        }
   357→        df
   358→    }
   359→    
   360→    fn column_names(&self) -> Vec<String> {
   361→        if let Some(basis) = &self.basis {
   362→            (0..basis.nbasis()).map(|i| format!("{}_{}", self.name, i + 1)).collect()
   363→        } else {
   364→            vec![self.name.clone()]
   365→        }
   366→    }
   367→    
   368→    fn as_any(&self) -> &dyn std::any::Any {
   369→        self
   370→    }
   371→    
   372→    fn clone_box(&self) -> Box<dyn EventSpec> {
   373→        // Create a new event with cloned data
   374→        let mut event = Event::new(self.name.clone(), self.onsets.to_vec());
   375→        
   376→        if let Some(ref durations) = self.durations {
   377→            event.durations = Some(durations.clone());
   378→        }
   379→        
   380→        if let Some(ref amplitudes) = self.amplitudes {
   381→            event.amplitudes = Some(amplitudes.clone());
   382→        }
   383→        
   384→        // Note: HRF and basis functions can't be cloned easily
   385→        // They would need to be recreated when needed
   386→        
   387→        Box::new(event)
   388→    }
   389→    
   390→    fn filter(&self, mask: &[bool]) -> Result<Box<dyn EventSpec>, ValidationError> {
   391→        if mask.len() != self.onsets.len() {
   392→            return Err(ValidationError::LengthMismatch {
   393→                expected: self.onsets.len(),
   394→                actual: mask.len(),
   395→            });
   396→        }
   397→        
   398→        let mut filtered_onsets = Vec::new();
   399→        let mut filtered_durations = Vec::new();
   400→        let mut filtered_amplitudes = Vec::new();
   401→        
   402→        for (i, &include) in mask.iter().enumerate() {
   403→            if include {
   404→                filtered_onsets.push(self.onsets[i]);
   405→                if let Some(ref durations) = self.durations {
   406→                    filtered_durations.push(durations[i]);
   407→                }
   408→                if let Some(ref amplitudes) = self.amplitudes {
   409→                    filtered_amplitudes.push(amplitudes[i]);
   410→                }
   411→            }
   412→        }
   413→        
   414→        if filtered_onsets.is_empty() {
   415→            return Err(ValidationError::InvalidParameter(
   416→                "Filter resulted in empty event".to_string()
   417→            ));
   418→        }
   419→        
   420→        let mut event = Event::new(self.name.clone(), filtered_onsets);
   421→        
   422→        if !filtered_durations.is_empty() && self.durations.is_some() {
   423→            event = event.with_durations(filtered_durations)?;
   424→        }
   425→        
   426→        if !filtered_amplitudes.is_empty() && self.amplitudes.is_some() {
   427→            event = event.with_amplitudes(filtered_amplitudes)?;
   428→        }
   429→        
   430→        // Note: basis functions can't be easily cloned
   431→        
   432→        Ok(Box::new(event))
   433→    }
   434→}
