   699→/// Factory function to create events from different specifications.
   700→pub fn create_event(
   701→    name: impl Into<String>,
   702→    onsets: Vec<f64>,
   703→    event_type: &str,
   704→    options: HashMap<String, String>,
   705→) -> Result<Box<dyn EventSpec>, ValidationError> {
   706→    let name = name.into();
   707→    
   708→    match event_type {
   709→        "simple" | "event" => {
   710→            let mut event = Event::new(name, onsets);
   711→            
   712→            // Add durations if specified
   713→            if let Some(dur_str) = options.get("durations") {
   714→                let durations: Result<Vec<f64>, _> = dur_str
   715→                    .split(',')
   716→                    .map(|s| s.trim().parse())
   717→                    .collect();
   718→                event = event.with_durations(durations.map_err(|_| {
   719→                    ValidationError::InvalidParameter("Invalid durations format".to_string())
   720→                })?)?;
   721→            }
   722→            
   723→            // Add amplitudes if specified
   724→            if let Some(amp_str) = options.get("amplitudes") {
   725→                let amplitudes: Result<Vec<f64>, _> = amp_str
   726→                    .split(',')
   727→                    .map(|s| s.trim().parse())
   728→                    .collect();
   729→                event = event.with_amplitudes(amplitudes.map_err(|_| {
   730→                    ValidationError::InvalidParameter("Invalid amplitudes format".to_string())
   731→                })?)?;
   732→            }
   733→            
   734→            // Add HRF if specified
   735→            if let Some(hrf_name) = options.get("hrf") {
   736→                let hrf = hrf::create_hrf_by_name(hrf_name)
   737→                    .ok_or_else(|| ValidationError::InvalidParameter(format!("Unknown HRF: {}", hrf_name)))?;
   738→                event = event.with_hrf(hrf);
   739→            }
   740→            
   741→            // Add basis if specified
   742→            if let Some(basis_type) = options.get("basis") {
   743→                use crate::basis::{PolynomialBasis, BSplineBasis};
   744→                
   745→                let basis: Box<dyn crate::types::BasisFunction> = match basis_type.as_str() {
   746→                    "polynomial" => {
   747→                        let degree = options.get("degree")
   748→                            .and_then(|s| s.parse().ok())
   749→                            .unwrap_or(3);
   750→                        Box::new(PolynomialBasis::new(degree))
   751→                    }
   752→                    "spline" | "bspline" => {
   753→                        let df = options.get("df")
   754→                            .and_then(|s| s.parse().ok())
   755→                            .unwrap_or(4);
   756→                        Box::new(BSplineBasis::new(df))
   757→                    }
   758→                    _ => return Err(ValidationError::InvalidParameter(
   759→                        format!("Unknown basis type: {}", basis_type)
   760→                    ))
   761→                };
   762→                event = event.with_basis(basis);
   763→            }
   764→            
   765→            Ok(Box::new(event))
   766→        }
   767→        "factor" | "categorical" => {
   768→            // For categorical events, we need values
   769→            let values_str = options.get("values")
   770→                .ok_or_else(|| ValidationError::InvalidParameter(
   771→                    "Categorical events require 'values' parameter".to_string()
   772→                ))?;
   773→            
   774→            let values: Vec<String> = values_str
   775→                .split(',')
   776→                .map(|s| s.trim().to_string())
   777→                .collect();
   778→            
   779→            if values.len() != onsets.len() {
   780→                return Err(ValidationError::LengthMismatch {
   781→                    expected: onsets.len(),
   782→                    actual: values.len(),
   783→                });
   784→            }
   785→            
   786→            // Create EventFactor
   787→            use crate::events::EventFactor;
   788→            
   789→            // Get durations if specified, otherwise use zeros
   790→            let durations = if let Some(dur_str) = options.get("durations") {
   791→                let durations: Result<Vec<f64>, _> = dur_str
   792→                    .split(',')
   793→                    .map(|s| s.trim().parse())
   794→                    .collect();
   795→                durations.map_err(|_| {
   796→                    ValidationError::InvalidParameter("Invalid durations format".to_string())
   797→                })?
   798→            } else {
   799→                vec![0.0; onsets.len()]
   800→            };
   801→            
   802→            let values_refs: Vec<&str> = values.iter().map(|s| s.as_str()).collect();
   803→            let factor = EventFactor::new(name, onsets, values_refs, durations)?;
   804→            Ok(Box::new(factor))
   805→        }
   806→        "variable" | "continuous" => {
   807→            // For continuous events, we need values
   808→            let values_str = options.get("values")
   809→                .ok_or_else(|| ValidationError::InvalidParameter(
   810→                    "Continuous events require 'values' parameter".to_string()
   811→                ))?;
   812→            
   813→            let values: Result<Vec<f64>, _> = values_str
   814→                .split(',')
   815→                .map(|s| s.trim().parse())
   816→                .collect();
   817→            
   818→            let values = values.map_err(|_| {
   819→                ValidationError::InvalidParameter("Invalid values format".to_string())
   820→            })?;
   821→            
   822→            if values.len() != onsets.len() {
   823→                return Err(ValidationError::LengthMismatch {
   824→                    expected: onsets.len(),
   825→                    actual: values.len(),
   826→                });
   827→            }
   828→            
   829→            // Get durations if specified, otherwise use zeros
   830→            let durations = if let Some(dur_str) = options.get("durations") {
   831→                let durations: Result<Vec<f64>, _> = dur_str
   832→                    .split(',')
   833→                    .map(|s| s.trim().parse())
   834→                    .collect();
   835→                durations.map_err(|_| {
   836→                    ValidationError::InvalidParameter("Invalid durations format".to_string())
   837→                })?
   838→            } else {
   839→                vec![0.0; onsets.len()]
   840→            };
   841→            
   842→            // Create EventVariable
   843→            use crate::events::EventVariable;
   844→            
   845→            let variable = EventVariable::new(name, onsets, values, durations)?;
   846→            Ok(Box::new(variable))
   847→        }
   848→        _ => Err(ValidationError::InvalidParameter(
   849→            format!("Unknown event type: {}", event_type)
   850→        ))
   851→    }
   852→}
