   854→// DataFrame implementation
   855→pub use crate::dataframe_polars::{DataFrame, DataFrameBuilder};
   856→
   857→    use crate::types::ValidationError;
   858→    use std::collections::HashMap;
   859→    
   860→    /// Simple DataFrame for event data
   861→    #[derive(Debug, Clone)]
   862→    pub struct DataFrame {
   863→        /// Numeric columns
   864→        pub columns: HashMap<String, Vec<f64>>,
   865→        /// String columns
   866→        pub str_columns: HashMap<String, Vec<String>>,
   867→        /// Column order (for consistent output)
   868→        column_order: Vec<String>,
   869→    }
   870→
   871→    impl DataFrame {
   872→        /// Create new DataFrame
   873→        pub fn new() -> Self {
   874→            Self {
   875→                columns: HashMap::new(),
   876→                str_columns: HashMap::new(),
   877→                column_order: Vec::new(),
   878→            }
   879→        }
   880→        
   881→        /// Add numeric column
   882→        pub fn add_column(&mut self, name: impl Into<String>, values: Vec<f64>) -> Result<(), ValidationError> {
   883→            let name = name.into();
   884→            let expected_len = self.validate_length(values.len())?;
   885→            if values.len() != expected_len {
   886→                return Err(ValidationError::LengthMismatch {
   887→                    expected: expected_len,
   888→                    actual: values.len(),
   889→                });
   890→            }
   891→            
   892→            if !self.column_order.contains(&name) {
   893→                self.column_order.push(name.clone());
   894→            }
   895→            self.columns.insert(name, values);
   896→            Ok(())
   897→        }
   898→        
   899→        /// Add string column
   900→        pub fn add_str_column(&mut self, name: impl Into<String>, values: Vec<String>) -> Result<(), ValidationError> {
   901→            let name = name.into();
   902→            let expected_len = self.validate_length(values.len())?;
   903→            if values.len() != expected_len {
   904→                return Err(ValidationError::LengthMismatch {
   905→                    expected: expected_len,
   906→                    actual: values.len(),
   907→                });
   908→            }
   909→            
   910→            if !self.column_order.contains(&name) {
   911→                self.column_order.push(name.clone());
   912→            }
   913→            self.str_columns.insert(name, values);
   914→            Ok(())
   915→        }
   916→        
   917→        /// Get numeric column
   918→        pub fn get_column(&self, name: &str) -> Option<Vec<f64>> {
   919→            self.columns.get(name).cloned()
   920→        }
   921→        
   922→        /// Get string column
   923→        pub fn get_str_column(&self, name: &str) -> Option<Vec<String>> {
   924→            self.str_columns.get(name).cloned()
   925→        }
   926→        
   927→        /// Get column names in order
   928→        pub fn column_names(&self) -> Vec<String> {
   929→            self.column_order.clone()
   930→        }
   931→        
   932→        /// Number of rows
   933→        pub fn len(&self) -> usize {
   934→            self.columns.values()
   935→                .map(|v| v.len())
   936→                .chain(self.str_columns.values().map(|v| v.len()))
   937→                .max()
   938→                .unwrap_or(0)
   939→        }
   940→        
   941→        /// Check if empty
   942→        pub fn is_empty(&self) -> bool {
   943→            self.len() == 0
   944→        }
   945→        
   946→        /// Validate column length consistency
   947→        fn validate_length(&self, new_len: usize) -> Result<usize, ValidationError> {
   948→            let current_len = self.len();
   949→            if current_len == 0 {
   950→                Ok(new_len)
   951→            } else if new_len == 0 {
   952→                Err(ValidationError::EmptyArray)
   953→            } else {
   954→                Ok(current_len)
   955→            }
   956→        }
   957→        
   958→        /// Get all string columns
   959→        pub fn string_columns(&self) -> HashMap<String, Vec<String>> {
   960→            self.str_columns.clone()
   961→        }
   962→        
   963→        /// Get all numeric columns
   964→        pub fn numeric_columns(&self) -> HashMap<String, Vec<f64>> {
   965→            self.columns.clone()
   966→        }
   967→        
