  1174→        all_event_names.extend(vec![event.name().to_string(); n_events]);
  1175→        all_event_types.extend(vec![format!("{:?}", event.event_type()); n_events]);
  1176→        
  1177→        // Handle event-specific data
  1178→        if let Some(levels) = event.levels() {
  1179→            // For categorical events, add level information
  1180→            if let Some(values) = event.values() {
  1181→                // We'll need to track these separately and merge later
  1182→            }
  1183→        }
