//! Core data structures for fmridesign.

use crate::types::{ValidationError, EventSpec, EventType, BasisFunction};
use crate::hrf;
use fmrihrf::{SamplingFrame, Hrf};
use ndarray::{Array1, Array2, ArrayView1, Axis};
use std::collections::HashMap;
use std::fmt;

// Import DataFrame based on feature flags - handled by pub use below

/// Main model struct that holds all events and generates design matrices.
#[derive(Debug)]
pub struct EventModel {
    /// List of events in the model
    pub events: Vec<Box<dyn EventSpec>>,
    /// Sampling frame
    pub sampling_frame: SamplingFrame,
    /// Name for the model
    pub name: String,
}

impl EventModel {
    /// Create a new EventModel.
    pub fn new(events: Vec<Box<dyn EventSpec>>, sampling_frame: SamplingFrame) -> Result<Self, ValidationError> {
        if events.is_empty() {
            return Err(ValidationError::InvalidParameter("EventModel requires at least one event".to_string()));
        }

        Ok(EventModel {
            events,
            sampling_frame,
            name: "EventModel".to_string(),
        })
    }

    /// Generate the design matrix.
    pub fn generate_design_matrix(&self) -> Result<Array2<f64>, ValidationError> {
        self.generate_design_matrix_impl(false)
    }

    /// Generate the design matrix with caching.
    pub fn generate_design_matrix_cached(&self) -> Result<Array2<f64>, ValidationError> {
        self.generate_design_matrix_impl(true)
    }

    /// Internal implementation of design matrix generation.
    fn generate_design_matrix_impl(&self, use_cache: bool) -> Result<Array2<f64>, ValidationError> {
        let mut columns = Vec::new();
        let mut column_names = Vec::new();

        // Get sampling points
        let sampling_points_vec = self.sampling_frame.samples();
        let n_samples = sampling_points_vec.len();
        let sampling_points = Array1::from_vec(sampling_points_vec);

        // Generate columns for each event
        for event in &self.events {
            let event_matrix = if use_cache {
                // Use cached computation
                self.generate_event_matrix_cached(event.as_ref(), &sampling_points)?
            } else {
                // Direct computation
                event.design_matrix(&sampling_points)?
            };

            let event_names = event.column_names();

            // Ensure correct dimensions
            if event_matrix.nrows() != n_samples {
                return Err(ValidationError::DimensionError {
                    expected: n_samples,
                    actual: event_matrix.nrows(),
                });
            }

            // Add columns
            for i in 0..event_matrix.ncols() {
                columns.push(event_matrix.column(i).to_owned());
                column_names.push(event_names.get(i).cloned().unwrap_or_else(|| format!("col_{}", i)));
            }
        }

        // Combine all columns into design matrix
        if columns.is_empty() {
            return Ok(Array2::zeros((n_samples, 0)));
        }

        let n_cols = columns.len();
        let mut design_matrix = Array2::zeros((n_samples, n_cols));

        for (i, col) in columns.into_iter().enumerate() {
            design_matrix.column_mut(i).assign(&col);
        }

        Ok(design_matrix)
    }

    /// Get column names for the design matrix.
    pub fn column_names(&self) -> Vec<String> {
        let mut names = Vec::new();
        for event in &self.events {
            names.extend(event.column_names());
        }
        names
    }

    /// Get the number of columns in the design matrix.
    pub fn n_columns(&self) -> usize {
        self.events.iter().map(|e| e.n_columns().unwrap_or(1)).sum()
    }

    /// Get the number of samples.
    pub fn n_samples(&self) -> usize {
        self.sampling_frame.n_scans()
    }

    /// Get a reference to the events.
    pub fn events(&self) -> &[Box<dyn EventSpec>] {
        &self.events
    }

    /// Get the number of events.
    pub fn n_events(&self) -> usize {
        self.events.len()
    }

    /// Add an event to the model.
    pub fn add_event(&mut self, event: Box<dyn EventSpec>) {
        self.events.push(event);
    }

    /// Set the model name.
    pub fn with_name(mut self, name: impl Into<String>) -> Self {
        self.name = name.into();
        self
    }

    /// Generate event matrix with caching.
    fn generate_event_matrix_cached(
        &self,
        event: &dyn EventSpec,
        sampling_points: &Array1<f64>,
    ) -> Result<Array2<f64>, ValidationError> {
        use crate::cache::{cached_design_matrix, hash_array};
        use std::collections::hash_map::DefaultHasher;
        use std::hash::{Hash, Hasher};

        // Create a hash of event parameters
        let mut hasher = DefaultHasher::new();
        event.name().hash(&mut hasher);
        event.event_type().hash(&mut hasher);
        event.n_events().hash(&mut hasher);

        // Hash event-specific data
        for &onset in event.onsets().iter() {
            ((onset * 1000.0) as i64).hash(&mut hasher);
        }
        for &duration in event.durations().iter() {
            ((duration * 1000.0) as i64).hash(&mut hasher);
        }

        let event_params_hash = hasher.finish();

        // Use cached computation
        cached_design_matrix(
            event.name(),
            sampling_points,
            event_params_hash,
            || event.design_matrix(sampling_points),
        )
    }

    /// Get column indices for each event/term.
    /// Returns a vector of (event_name, column_indices) tuples.
    pub fn column_indices(&self) -> Result<Vec<(String, Vec<usize>)>, ValidationError> {
        let mut result = Vec::new();
        let mut current_idx = 0;

        for event in &self.events {
            let n_cols = event.n_columns().unwrap_or(1);
            let indices: Vec<usize> = (current_idx..current_idx + n_cols).collect();
            result.push((event.name().to_string(), indices));
            current_idx += n_cols;
        }

        Ok(result)
    }
}

impl fmt::Display for EventModel {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        writeln!(f, "EventModel '{}' with {} events:", self.name, self.events.len())?;
        for (i, event) in self.events.iter().enumerate() {
            writeln!(f, "  {}: {} ({:?})", i, event.name(), event.event_type())?;
        }
        writeln!(f, "Sampling: {} samples", self.n_samples())?;
        writeln!(f, "Design matrix: {} x {}", self.n_samples(), self.n_columns())?;
        Ok(())
    }
}

/// An event that can contribute columns to a design matrix.
#[derive(Debug)]
pub struct Event {
    /// Event name
    pub name: String,
    /// Event onsets
    pub onsets: Array1<f64>,
    /// Event durations (optional, defaults to 0)
    pub durations: Option<Array1<f64>>,
    /// Event amplitudes (optional, defaults to 1)
    pub amplitudes: Option<Array1<f64>>,
    /// HRF for convolution (optional)
    pub hrf: Option<Box<dyn Hrf>>,
    /// Basis function for continuous events (optional)
    pub basis: Option<Box<dyn BasisFunction>>,
}

impl Event {
    /// Create a new event.
    pub fn new(name: impl Into<String>, onsets: Vec<f64>) -> Self {
        Event {
            name: name.into(),
            onsets: Array1::from_vec(onsets),
            durations: None,
            amplitudes: None,
            hrf: None,
            basis: None,
        }
    }

    /// Set durations.
    pub fn with_durations(mut self, durations: Vec<f64>) -> Result<Self, ValidationError> {
        if durations.len() != self.onsets.len() {
            return Err(ValidationError::LengthMismatch {
                expected: self.onsets.len(),
                actual: durations.len(),
            });
        }
        self.durations = Some(Array1::from_vec(durations));
        Ok(self)
    }

    /// Set amplitudes.
    pub fn with_amplitudes(mut self, amplitudes: Vec<f64>) -> Result<Self, ValidationError> {
        if amplitudes.len() != self.onsets.len() {
            return Err(ValidationError::LengthMismatch {
                expected: self.onsets.len(),
                actual: amplitudes.len(),
            });
        }
        self.amplitudes = Some(Array1::from_vec(amplitudes));
        Ok(self)
    }

    /// Set HRF for convolution.
    pub fn with_hrf(mut self, hrf: Box<dyn Hrf>) -> Self {
        self.hrf = Some(hrf);
        self
    }

    /// Set basis function for continuous values.
    pub fn with_basis(mut self, basis: Box<dyn BasisFunction>) -> Self {
        self.basis = Some(basis);
        self
    }
}

impl EventSpec for Event {
    fn name(&self) -> &str {
        &self.name
    }

    fn event_type(&self) -> EventType {
        EventType::Continuous
    }

    fn design_matrix(&self, sampling_points: &Array1<f64>) -> Result<Array2<f64>, ValidationError> {
        let n_samples = sampling_points.len();
        let durations = self.durations.as_ref();
        let amplitudes = self.amplitudes.as_ref();

        // Create base regressor (before any transformations)
        let mut regressor = Array1::zeros(n_samples);
        let tr = 2.0; // Default TR, should be provided differently

        for (i, &onset) in self.onsets.iter().enumerate() {
            let duration = durations.as_ref().and_then(|d| d.get(i)).copied().unwrap_or(0.0);
            let amplitude = amplitudes.as_ref().and_then(|a| a.get(i)).copied().unwrap_or(1.0);

            // Find samples that overlap with this event
            for (j, &t) in sampling_points.iter().enumerate() {
                // Check if this sample overlaps with the event
                // Using the same logic as the original implementation
                let sample_start = t - tr / 2.0;
                let sample_end = t + tr / 2.0;

                if sample_end > onset && sample_start < onset + duration {
                    regressor[j] += amplitude;
                }
            }
        }

        // Apply HRF convolution if specified
        let convolved = if let Some(hrf) = &self.hrf {
            // Simple discrete convolution
            let hrf_samples = Array1::linspace(0.0, 30.0, 301);
            let hrf_values = hrf.evaluate(&hrf_samples)
                .map_err(|e| ValidationError::InvalidParameter(format!("HRF evaluation failed: {}", e)))?;

            // For now, use the first column if HRF returns multiple
            let hrf_vec = hrf_values.column(0);

            // Convolve using discrete convolution
            let precision = 0.1; // Default precision
            convolve_discrete(&regressor.view(), &hrf_vec.view(), precision, tr)
        } else {
            regressor
        };

        // Apply basis function if specified
        let final_matrix = if let Some(basis) = &self.basis {
            // Apply basis function to the convolved regressor
            let basis_matrix = basis.evaluate(&convolved.view())?;
            basis_matrix
        } else {
            // Return as single column matrix
            convolved.insert_axis(Axis(1))
        };

        Ok(final_matrix)
    }

    fn onsets(&self) -> &Array1<f64> {
        &self.onsets
    }

    fn durations(&self) -> &Array1<f64> {
        // Return empty array if no durations
        self.durations.as_ref().unwrap_or(&self.onsets)
    }

    fn n_columns(&self) -> Option<usize> {
        Some(self.basis.as_ref().map(|b| b.nbasis()).unwrap_or(1))
    }

    fn to_dataframe(&self) -> crate::core::DataFrame {
        let mut df = DataFrame::new();
        let _ = df.add_column("onset", self.onsets.to_vec());
        if let Some(durations) = &self.durations {
            let _ = df.add_column("duration", durations.to_vec());
        }
        if let Some(amplitudes) = &self.amplitudes {
            let _ = df.add_column("amplitude", amplitudes.to_vec());
        }
        df
    }

    fn column_names(&self) -> Vec<String> {
        if let Some(basis) = &self.basis {
            (0..basis.nbasis()).map(|i| format!("{}_{}", self.name, i + 1)).collect()
        } else {
            vec![self.name.clone()]
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }

    fn clone_box(&self) -> Box<dyn EventSpec> {
        // Create a new event with cloned data
        let mut event = Event::new(self.name.clone(), self.onsets.to_vec());

        if let Some(ref durations) = self.durations {
            event.durations = Some(durations.clone());
        }

        if let Some(ref amplitudes) = self.amplitudes {
            event.amplitudes = Some(amplitudes.clone());
        }

        // Note: HRF and basis functions can't be cloned easily
        // They would need to be recreated when needed

        Box::new(event)
    }

    fn filter(&self, mask: &[bool]) -> Result<Box<dyn EventSpec>, ValidationError> {
        if mask.len() != self.onsets.len() {
            return Err(ValidationError::LengthMismatch {
                expected: self.onsets.len(),
                actual: mask.len(),
            });
        }

        let mut filtered_onsets = Vec::new();
        let mut filtered_durations = Vec::new();
        let mut filtered_amplitudes = Vec::new();

        for (i, &include) in mask.iter().enumerate() {
            if include {
                filtered_onsets.push(self.onsets[i]);
                if let Some(ref durations) = self.durations {
                    filtered_durations.push(durations[i]);
                }
                if let Some(ref amplitudes) = self.amplitudes {
                    filtered_amplitudes.push(amplitudes[i]);
                }
            }
        }

        if filtered_onsets.is_empty() {
            return Err(ValidationError::InvalidParameter(
                "Filter resulted in empty event".to_string()
            ));
        }

        let mut event = Event::new(self.name.clone(), filtered_onsets);

        if !filtered_durations.is_empty() && self.durations.is_some() {
            event = event.with_durations(filtered_durations)?;
        }

        if !filtered_amplitudes.is_empty() && self.amplitudes.is_some() {
            event = event.with_amplitudes(filtered_amplitudes)?;
        }

        // Note: basis functions can't be easily cloned

        Ok(Box::new(event))
    }
}

/// Simple discrete convolution function
fn convolve_discrete(signal: &ArrayView1<f64>, kernel: &ArrayView1<f64>, precision: f64, _tr: f64) -> Array1<f64> {
    let signal_len = signal.len();
    let kernel_len = kernel.len();

    let mut result = Array1::zeros(signal_len);

    for i in 0..signal_len {
        let mut sum = 0.0;
        for j in 0..kernel_len.min(i + 1) {
            if i >= j {
                sum += signal[i - j] * kernel[j] * precision;
            }
        }
        result[i] = sum;
    }

    result
}

