    23→impl EventModel {
    24→    /// Create a new EventModel.
    25→    pub fn new(events: Vec<Box<dyn EventSpec>>, sampling_frame: SamplingFrame) -> Result<Self, ValidationError> {
    26→        if events.is_empty() {
    27→            return Err(ValidationError::InvalidParameter("EventModel requires at least one event".to_string()));
    28→        }
