    37→    /// Generate the design matrix.
    38→    pub fn generate_design_matrix(&self) -> Result<Array2<f64>, ValidationError> {
    39→        self.generate_design_matrix_impl(false)
    40→    }
    41→    
    42→    /// Generate the design matrix with caching.
    43→    pub fn generate_design_matrix_cached(&self) -> Result<Array2<f64>, ValidationError> {
    44→        self.generate_design_matrix_impl(true)
    45→    }
