   159→        for &duration in event.durations().iter() {
   160→            ((duration * 1000.0) as i64).hash(&mut hasher);
   161→        }
   162→        
   163→        let event_params_hash = hasher.finish();
   164→        
   165→        // Use cached computation
   166→        cached_design_matrix(
   167→            event.name(),
   168→            sampling_points,
   169→            event_params_hash,
   170→            || event.design_matrix(sampling_points),
   171→        )
   172→    }
