   436→/// Simple discrete convolution function
   437→fn convolve_discrete(signal: &ArrayView1<f64>, kernel: &ArrayView1<f64>, precision: f64, _tr: f64) -> Array1<f64> {
   438→    let signal_len = signal.len();
   439→    let kernel_len = kernel.len();
   440→    
   441→    let mut result = Array1::zeros(signal_len);
   442→    
   443→    for i in 0..signal_len {
   444→        let mut sum = 0.0;
   445→        for j in 0..kernel_len.min(i + 1) {
   446→            if i >= j {
   447→                sum += signal[i - j] * kernel[j] * precision;
   448→            }
   449→        }
   450→        result[i] = sum;
   451→    }
   452→    
   453→    result
   454→}
