   513→/// Baseline model for drift correction.
   514→#[derive(Debug)]
   515→pub struct BaselineModel {
   516→    /// Basis function for the baseline
   517→    pub basis: Box<dyn BasisFunction>,
   518→    /// Model name
   519→    pub name: String,
   520→}
   521→
   522→impl BaselineModel {
   523→    /// Create a new baseline model.
   524→    pub fn new(basis: Box<dyn BasisFunction>) -> Self {
   525→        let name = format!("Baseline[{}]", basis.name());
   526→        BaselineModel { basis, name }
   527→    }
   528→    
   529→    /// Create polynomial baseline model.
   530→    pub fn polynomial(degree: usize) -> Self {
   531→        use crate::basis::PolynomialBasis;
   532→        let basis = Box::new(PolynomialBasis::new(degree).with_intercept(true));
   533→        Self::new(basis)
   534→    }
   535→    
   536→    /// Create spline baseline model.
   537→    pub fn spline(df: usize) -> Self {
   538→        use crate::basis::BSplineBasis;
   539→        let basis = Box::new(BSplineBasis::new(df));
   540→        Self::new(basis)
   541→    }
   542→    
   543→    /// Generate baseline design matrix.
   544→    pub fn design_matrix(&self, sampling_frame: &SamplingFrame) -> Result<Array2<f64>, ValidationError> {
   545→        let samples = sampling_frame.samples();
   546→        let n_samples = samples.len();
   547→        
   548→        // Create time vector normalized to [0, 1]
   549→        let duration = if samples.is_empty() {
   550→            1.0
   551→        } else {
   552→            samples[samples.len() - 1] - samples[0]
   553→        };
   554→        let normalized_time = Array1::from_vec(
   555→            samples.iter()
   556→                .map(|&t| (t - samples[0]) / duration)
   557→                .collect()
   558→        );
   559→        
   560→        // Apply basis function
   561→        self.basis.evaluate(&normalized_time.view())
   562→    }
   563→    
   564→    /// Get column names.
   565→    pub fn column_names(&self) -> Vec<String> {
   566→        (0..self.basis.nbasis())
   567→            .map(|i| format!("{}_{}", self.name, i + 1))
   568→            .collect()
   569→    }
   570→}
   571→
   572→impl fmt::Display for BaselineModel {
   573→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
   574→        write!(f, "{} with {} basis functions", self.name, self.basis.nbasis())
   575→    }
   576→}
