   578→/// Combined model with events and baseline.
   579→#[derive(Debug)]
   580→pub struct DesignMatrix {
   581→    /// Event model
   582→    pub event_model: EventModel,
   583→    /// Baseline model (optional)
   584→    pub baseline_model: Option<BaselineModel>,
   585→    /// Cached design matrix
   586→    cached_matrix: Option<Array2<f64>>,
   587→    /// Cached column names
   588→    cached_names: Option<Vec<String>>,
   589→}
   590→
   591→impl DesignMatrix {
   592→    /// Create from event model.
   593→    pub fn from_event_model(event_model: EventModel) -> Self {
   594→        DesignMatrix {
   595→            event_model,
   596→            baseline_model: None,
   597→            cached_matrix: None,
   598→            cached_names: None,
   599→        }
   600→    }
   601→    
   602→    /// Add baseline model.
   603→    pub fn with_baseline(mut self, baseline: BaselineModel) -> Self {
   604→        self.baseline_model = Some(baseline);
   605→        self.cached_matrix = None;
   606→        self.cached_names = None;
   607→        self
   608→    }
   609→    
   610→    /// Get the full design matrix.
   611→    pub fn matrix(&mut self) -> Result<&Array2<f64>, ValidationError> {
   612→        if self.cached_matrix.is_none() {
   613→            self.generate_matrix()?;
   614→        }
   615→        Ok(self.cached_matrix.as_ref().unwrap())
   616→    }
   617→    
   618→    /// Get column names.
   619→    pub fn column_names(&mut self) -> Result<&Vec<String>, ValidationError> {
   620→        if self.cached_names.is_none() {
   621→            self.generate_matrix()?;
   622→        }
   623→        Ok(self.cached_names.as_ref().unwrap())
   624→    }
   625→    
   626→    /// Generate the combined matrix.
   627→    fn generate_matrix(&mut self) -> Result<(), ValidationError> {
   628→        let event_matrix = self.event_model.generate_design_matrix()?;
   629→        let mut column_names = self.event_model.column_names();
   630→        
   631→        let combined_matrix = if let Some(baseline) = &self.baseline_model {
   632→            let baseline_matrix = baseline.design_matrix(&self.event_model.sampling_frame)?;
   633→            let baseline_names = baseline.column_names();
   634→            
   635→            // Ensure same number of rows
   636→            if event_matrix.nrows() != baseline_matrix.nrows() {
   637→                return Err(ValidationError::DimensionError {
   638→                    expected: event_matrix.nrows(),
   639→                    actual: baseline_matrix.nrows(),
   640→                });
   641→            }
   642→            
   643→            // Concatenate matrices
   644→            let n_rows = event_matrix.nrows();
   645→            let n_event_cols = event_matrix.ncols();
   646→            let n_baseline_cols = baseline_matrix.ncols();
   647→            let n_total_cols = n_event_cols + n_baseline_cols;
   648→            
   649→            let mut combined = Array2::zeros((n_rows, n_total_cols));
   650→            
   651→            // Copy event columns
   652→            for i in 0..n_event_cols {
   653→                combined.column_mut(i).assign(&event_matrix.column(i));
   654→            }
   655→            
   656→            // Copy baseline columns
   657→            for i in 0..n_baseline_cols {
   658→                combined.column_mut(n_event_cols + i).assign(&baseline_matrix.column(i));
   659→            }
   660→            
   661→            column_names.extend(baseline_names);
   662→            combined
   663→        } else {
   664→            event_matrix
   665→        };
   666→        
   667→        self.cached_matrix = Some(combined_matrix);
   668→        self.cached_names = Some(column_names);
   669→        
   670→        Ok(())
   671→    }
   672→}
   673→
   674→impl fmt::Display for DesignMatrix {
   675→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
   676→        write!(f, "DesignMatrix with {} events", self.event_model.n_events())?;
   677→        if self.baseline_model.is_some() {
   678→            write!(f, " and baseline model")?;
   679→        }
   680→        
   681→        if let (Some(matrix), Some(names)) = (&self.cached_matrix, &self.cached_names) {
   682→            write!(f, "\nShape: {} x {}", matrix.nrows(), matrix.ncols())?;
   683→            write!(f, "\nColumns: {}", names.join(", "))?;
   684→        } else {
   685→            let n_cols = self.event_model.n_columns() + 
   686→                self.baseline_model.as_ref().map(|b| b.basis.nbasis()).unwrap_or(0);
   687→            write!(
   688→                f,
   689→                "\nExpected shape: {} x {}",
   690→                self.event_model.n_samples(),
   691→                n_cols
   692→            )?;
   693→        }
   694→        
   695→        Ok(())
   696→    }
   697→}
