   856→
   857→
   858→    impl DataFrame {
   859→        /// Create new DataFrame
   860→        pub fn new() -> Self {
   861→            Self {
   862→                columns: HashMap::new(),
   863→                str_columns: HashMap::new(),
   864→                column_order: Vec::new(),
   865→            }
   866→        }
   867→        
   868→        /// Add numeric column
   869→        pub fn add_column(&mut self, name: impl Into<String>, values: Vec<f64>) -> Result<(), ValidationError> {
   870→            let name = name.into();
   871→            let expected_len = self.validate_length(values.len())?;
   872→            if values.len() != expected_len {
   873→                return Err(ValidationError::LengthMismatch {
   874→                    expected: expected_len,
   875→                    actual: values.len(),
   876→                });
   877→            }
   878→            
   879→            if !self.column_order.contains(&name) {
   880→                self.column_order.push(name.clone());
   881→            }
   882→            self.columns.insert(name, values);
   883→            Ok(())
   884→        }
   885→        
   886→        /// Add string column
   887→        pub fn add_str_column(&mut self, name: impl Into<String>, values: Vec<String>) -> Result<(), ValidationError> {
   888→            let name = name.into();
   889→            let expected_len = self.validate_length(values.len())?;
   890→            if values.len() != expected_len {
   891→                return Err(ValidationError::LengthMismatch {
   892→                    expected: expected_len,
   893→                    actual: values.len(),
   894→                });
   895→            }
   896→            
   897→            if !self.column_order.contains(&name) {
   898→                self.column_order.push(name.clone());
   899→            }
   900→            self.str_columns.insert(name, values);
   901→            Ok(())
   902→        }
   903→        
   904→        /// Get numeric column
   905→        pub fn get_column(&self, name: &str) -> Option<Vec<f64>> {
   906→            self.columns.get(name).cloned()
   907→        }
   908→        
   909→        /// Get string column
   910→        pub fn get_str_column(&self, name: &str) -> Option<Vec<String>> {
   911→            self.str_columns.get(name).cloned()
   912→        }
   913→        
   914→        /// Get column names in order
   915→        pub fn column_names(&self) -> Vec<String> {
   916→            self.column_order.clone()
   917→        }
   918→        
   919→        /// Number of rows
   920→        pub fn len(&self) -> usize {
   921→            self.columns.values()
   922→                .map(|v| v.len())
   923→                .chain(self.str_columns.values().map(|v| v.len()))
   924→                .max()
   925→                .unwrap_or(0)
   926→        }
   927→        
   928→        /// Check if empty
   929→        pub fn is_empty(&self) -> bool {
   930→            self.len() == 0
   931→        }
   932→        
   933→        /// Validate column length consistency
   934→        fn validate_length(&self, new_len: usize) -> Result<usize, ValidationError> {
   935→            let current_len = self.len();
   936→            if current_len == 0 {
   937→                Ok(new_len)
   938→            } else if new_len == 0 {
   939→                Err(ValidationError::EmptyArray)
   940→            } else {
   941→                Ok(current_len)
   942→            }
   943→        }
   944→        
   945→        /// Get all string columns
   946→        pub fn string_columns(&self) -> HashMap<String, Vec<String>> {
   947→            self.str_columns.clone()
   948→        }
   949→        
   950→        /// Get all numeric columns
   951→        pub fn numeric_columns(&self) -> HashMap<String, Vec<f64>> {
   952→            self.columns.clone()
   953→        }
   954→        
   955→        /// Get column as strings (works for both numeric and string columns)
   956→        pub fn get(&self, name: &str) -> Option<Vec<String>> {
   957→            if let Some(values) = self.str_columns.get(name) {
   958→                Some(values.clone())
   959→            } else if let Some(values) = self.columns.get(name) {
   960→                Some(values.iter().map(|v| v.to_string()).collect())
   961→            } else {
   962→                None
   963→            }
   964→        }
   965→        
   966→        /// Insert a column (converts strings to appropriate type)
   967→        pub fn insert(&mut self, name: impl Into<String>, values: Vec<&str>) {
   968→            let name = name.into();
   969→            
   970→            // Try to parse as numeric first
   971→            let numeric_values: Result<Vec<f64>, _> = values.iter()
   972→                .map(|s| s.parse::<f64>())
   973→                .collect();
   974→            
   975→            if let Ok(nums) = numeric_values {
   976→                let _ = self.add_column(name, nums);
   977→            } else {
   978→                // Store as strings
   979→                let string_values: Vec<String> = values.into_iter()
   980→                    .map(|s| s.to_string())
   981→                    .collect();
   982→                let _ = self.add_str_column(name, string_values);
   983→            }
   984→        }
   985→        
   986→        /// Iterate over all columns
   987→        pub fn iter(&self) -> impl Iterator<Item = (String, Vec<String>)> + '_ {
   988→            self.column_order.iter().map(move |name| {
   989→                let values = self.get(name).unwrap_or_default();
   990→                (name.clone(), values)
   991→            })
   992→        }
   993→        
   994→        /// Get unique values in a column
   995→        pub fn unique(&self, column: &str) -> Result<Vec<String>, ValidationError> {
   996→            let values = self.get(column)
   997→                .ok_or_else(|| ValidationError::MissingColumn(column.to_string()))?;
   998→            
   999→            let mut unique_values: Vec<String> = values.into_iter()
  1000→                .collect::<std::collections::HashSet<_>>()
  1001→                .into_iter()
  1002→                .collect();
  1003→            unique_values.sort();
  1004→            
  1005→            Ok(unique_values)
  1006→        }
  1007→        
  1008→        /// Select columns
  1009→        pub fn select<I, S>(&self, columns: I) -> Result<DataFrame, ValidationError>
  1010→        where
  1011→            I: IntoIterator<Item = S>,
  1012→            S: AsRef<str>,
  1013→        {
  1014→            let mut new_df = DataFrame::new();
  1015→            
  1016→            for col_name in columns {
  1017→                let col_name = col_name.as_ref();
  1018→                
  1019→                if let Some(values) = self.columns.get(col_name) {
  1020→                    new_df.add_column(col_name, values.clone())?;
  1021→                } else if let Some(values) = self.str_columns.get(col_name) {
  1022→                    new_df.add_str_column(col_name, values.clone())?;
  1023→                } else {
