  1161→        all_event_names.extend(vec![event.name().to_string(); n_events]);
  1162→        all_event_types.extend(vec![format!("{:?}", event.event_type()); n_events]);
  1163→        
  1164→        // Handle event-specific data
  1165→        if let Some(levels) = event.levels() {
  1166→            // For categorical events, add level information
  1167→            if let Some(values) = event.values() {
  1168→                // We'll need to track these separately and merge later
  1169→            }
  1170→        }
