  1179→    // Create sorted data
  1180→    let sorted_onsets: Vec<f64> = indices.iter().map(|&i| all_onsets[i]).collect();
  1181→    let sorted_durations: Vec<f64> = indices.iter().map(|&i| all_durations[i]).collect();
  1182→    let sorted_names: Vec<String> = indices.iter().map(|&i| all_event_names[i].clone()).collect();
  1183→    let sorted_types: Vec<String> = indices.iter().map(|&i| all_event_types[i].clone()).collect();
