//! Cached convolution operations for improved performance.

use ndarray::{Array1, Array2};
use crate::types::{EventSpec, Array, ValidationError};
use crate::cache::{cached_hrf_convolution, cached_design_matrix, hash_array, CacheKey};
use crate::convolve::{ConvolveOptions, get_hrf_array};
use fmrihrf::Hrf;
use std::collections::hash_map::DefaultHasher;
use std::hash::{Hash, Hasher};

/// Cached convolution of event with HRF.
pub fn convolve_cached(
    event: &dyn EventSpec,
    hrf: &dyn Hrf,
    sampling_points: &Array1<f64>,
    options: &ConvolveOptions,
) -> Result<Array2<f64>, ValidationError> {
    // Create a hash of the event parameters
    let mut hasher = DefaultHasher::new();
    event.name().hash(&mut hasher);
    event.n_events().hash(&mut hasher);

    // Hash onsets and durations
    for &onset in event.onsets().iter() {
        ((onset * 1000.0) as i64).hash(&mut hasher);
    }
    for &duration in event.durations().iter() {
        ((duration * 1000.0) as i64).hash(&mut hasher);
    }

    let event_params_hash = hasher.finish();

    // Try to get HRF name for cache key
    let hrf_name = format!("hrf_{:x}", hasher.finish()); // Simple hash-based name

    // Use cached design matrix computation
    cached_design_matrix(
        event.name(),
        sampling_points,
        event_params_hash,
        || {
            // Compute design matrix without cache
            compute_convolved_design_matrix(event, hrf, sampling_points, options)
        },
    )
}

/// Compute convolved design matrix (the actual computation).
fn compute_convolved_design_matrix(
    event: &dyn EventSpec,
    hrf: &dyn Hrf,
    sampling_points: &Array1<f64>,
    options: &ConvolveOptions,
) -> Result<Array2<f64>, ValidationError> {
    // First get the raw event design matrix
    let raw_dm = event.design_matrix(sampling_points)?;

    // Get HRF kernel
    let hrf_kernel = get_hrf_array(hrf, 1.0 / options.precision, options.hrf_duration)?;

    // Convolve each column
    let n_rows = raw_dm.nrows();
    let n_cols = raw_dm.ncols();
    let mut convolved_dm = Array2::zeros((n_rows, n_cols));

    for col_idx in 0..n_cols {
        let col = raw_dm.column(col_idx);

        // Create unique cache key for this column
        let col_name = format!("{}_{}", event.name(), col_idx);

        // Use cached HRF convolution for this column
        let convolved = cached_hrf_convolution(
            &col_name,
            &format!("hrf_{}", col_idx),
            &col.to_owned(),
            sampling_points,
            || convolve_column(&col, &hrf_kernel, options),
        )?;

        convolved_dm.column_mut(col_idx).assign(&convolved);
    }

    Ok(convolved_dm)
}

/// Convolve a single column with HRF.
fn convolve_column(
    column: &ArrayView1<f64>,
    hrf_kernel: &Array1<f64>,
    options: &ConvolveOptions,
) -> Result<Array1<f64>, ValidationError> {
    use ndarray::s;

    // Upsample the column to precision grid
    let n_samples = column.len();
    let upsampling_factor = (options.sampling_rate / options.precision).round() as usize;
    let n_upsampled = n_samples * upsampling_factor;

    let mut upsampled = Array1::zeros(n_upsampled);
    for (i, &val) in column.iter().enumerate() {
        upsampled[i * upsampling_factor] = val;
    }

    // Perform convolution
    let convolved = match options.method.as_str() {
        "fft" => convolve_fft(&upsampled, hrf_kernel)?,
        _ => convolve_direct(&upsampled, hrf_kernel)?,
    };

    // Downsample back to original sampling rate
    let mut result = Array1::zeros(n_samples);
    for i in 0..n_samples {
        let idx = i * upsampling_factor;
        if idx < convolved.len() {
            result[i] = convolved[idx];
        }
    }

    Ok(result)
}

/// Direct convolution implementation.
fn convolve_direct(signal: &Array1<f64>, kernel: &Array1<f64>) -> Result<Array1<f64>, ValidationError> {
    let n_signal = signal.len();
    let n_kernel = kernel.len();
    let n_output = n_signal + n_kernel - 1;

    let mut output = Array1::zeros(n_output);

    for i in 0..n_signal {
        for j in 0..n_kernel {
            if i + j < n_output {
                output[i + j] += signal[i] * kernel[j];
            }
        }
    }

    // Trim to original signal length
    Ok(output.slice(ndarray::s![..n_signal]).to_owned())
}

/// FFT-based convolution (placeholder - would need FFT library).
fn convolve_fft(signal: &Array1<f64>, kernel: &Array1<f64>) -> Result<Array1<f64>, ValidationError> {
    // For now, fall back to direct convolution
    // In a real implementation, we'd use an FFT library like rustfft
    convolve_direct(signal, kernel)
}

/// Cache-aware event model that uses caching for design matrix generation.
pub struct CachedEventModel {
    events: Vec<Box<dyn EventSpec>>,
    sampling_frame: fmrihrf::SamplingFrame,
}

impl CachedEventModel {
    /// Create a new cached event model.
    pub fn new(events: Vec<Box<dyn EventSpec>>, sampling_frame: fmrihrf::SamplingFrame) -> Self {
        Self {
            events,
            sampling_frame,
        }
    }

    /// Generate design matrix with caching.
    pub fn generate_design_matrix(&self) -> Result<Array2<f64>, ValidationError> {
        let sampling_points_vec = self.sampling_frame.samples();
        let n_points = sampling_points_vec.len();
        let sampling_points = Array1::from_vec(sampling_points_vec);

        // Collect all columns
        let mut all_columns = Vec::new();

        for event in &self.events {
            // Use cached design matrix generation
            let dm = cached_design_matrix(
                event.name(),
                &sampling_points,
                0, // No special params for now
                || event.design_matrix(&sampling_points),
            )?;

            for col_idx in 0..dm.ncols() {
                all_columns.push(dm.column(col_idx).to_owned());
            }
        }

        // Combine columns into design matrix
        if all_columns.is_empty() {
            Ok(Array2::zeros((n_points, 0)))
        } else {
            let n_cols = all_columns.len();
            let mut design_matrix = Array2::zeros((n_points, n_cols));

            for (j, col) in all_columns.iter().enumerate() {
                design_matrix.column_mut(j).assign(col);
            }

            Ok(design_matrix)
        }
    }

    /// Clear caches related to this model.
    pub fn clear_caches(&self) {
        use crate::cache::GLOBAL_CACHE;

        // In a more sophisticated implementation, we could clear only
        // the cache entries related to this model's events
        GLOBAL_CACHE.design_matrix_cache.clear();
        GLOBAL_CACHE.hrf_cache.clear();
    }

    /// Get cache statistics.
    pub fn cache_stats() -> crate::cache::CacheStats {
        use crate::cache::GLOBAL_CACHE;
        GLOBAL_CACHE.combined_stats()
    }
}

use ndarray::ArrayView1;

/// Precompute and cache HRF kernels for common configurations.
pub fn precompute_hrf_cache(
    hrf_specs: &[&str],
    sampling_rates: &[f64],
    durations: &[f64],
) -> Result<(), ValidationError> {
    use crate::cache::GLOBAL_CACHE;

    for &hrf_name in hrf_specs {
        let hrf = crate::hrf::get_hrf(hrf_name, &Default::default())?;

        for &sr in sampling_rates {
            for &duration in durations {
                let kernel = get_hrf_array(hrf.as_ref(), sr, duration)?;

                // Create a dummy event to cache the HRF
                let key = CacheKey::Custom(format!("hrf_kernel_{}_{:.1}_{:.1}", hrf_name, sr, duration));
                let size = std::mem::size_of::<f64>() * kernel.len();

                GLOBAL_CACHE.hrf_cache.insert(key, kernel, Some(size));
            }
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::events::EventVariable;
    use crate::cache::GLOBAL_CACHE;

    #[test]
    fn test_cached_convolution() {
        // Clear caches first
        GLOBAL_CACHE.clear_all();

        // Create a simple event
        let event = EventVariable::new(
            "test_event",
            vec![1.0, 5.0, 10.0],
            vec![1.0, 2.0, 3.0],
            vec![0.5, 0.5, 0.5],
        ).unwrap();

        // Create HRF
        let hrf = hrf_lib::canonical_hrf();

        // Create sampling points
        let sampling_points = Array1::linspace(0.0, 20.0, 100);

        // First call should miss cache
        let stats_before = GLOBAL_CACHE.design_matrix_cache.stats();
        let result1 = convolve_cached(
            &event,
            &hrf,
            &sampling_points,
            &ConvolveOptions::default(),
        ).unwrap();
        let stats_after1 = GLOBAL_CACHE.design_matrix_cache.stats();

        assert_eq!(stats_after1.misses - stats_before.misses, 1);

        // Second call should hit cache
        let result2 = convolve_cached(
            &event,
            &hrf,
            &sampling_points,
            &ConvolveOptions::default(),
        ).unwrap();
        let stats_after2 = GLOBAL_CACHE.design_matrix_cache.stats();

        assert_eq!(stats_after2.hits - stats_after1.hits, 1);

        // Results should be identical
        assert_eq!(result1, result2);
    }

    #[test]
    fn test_precompute_cache() {
        GLOBAL_CACHE.clear_all();

        let hrfs = vec!["canonical", "gamma"];
        let srs = vec![1.0, 2.0];
        let durations = vec![32.0];

        precompute_hrf_cache(&hrfs, &srs, &durations).unwrap();

        // Check that cache has entries
        assert!(GLOBAL_CACHE.hrf_cache.len() > 0);
    }
}

