    10→/// Standard scaling transformation (z-score).
    11→///
    12→/// Centers and scales values to have mean 0 and standard deviation 1.
    13→#[derive(Debug, Clone)]
    14→pub struct Scale {
    15→    /// Whether to center (subtract mean).
    16→    pub center: bool,
    17→    /// Whether to scale (divide by standard deviation).
    18→    pub scale: bool,
    19→    /// Name for the transformation.
    20→    pub name: String,
    21→    /// Computed mean (after evaluation).
    22→    mean: Option<f64>,
    23→    /// Computed standard deviation (after evaluation).
    24→    std: Option<f64>,
    25→}
    26→
    27→impl Scale {
    28→    /// Create a new Scale transformation.
    29→    pub fn new(center: bool, scale: bool) -> Self {
    30→        Self {
    31→            center,
    32→            scale,
    33→            name: "scale".to_string(),
    34→            mean: None,
    35→            std: None,
    36→        }
    37→    }
    38→    
    39→    /// Create with custom name.
    40→    pub fn with_name(center: bool, scale: bool, name: &str) -> Self {
    41→        Self {
    42→            center,
    43→            scale,
    44→            name: name.to_string(),
    45→            mean: None,
    46→            std: None,
    47→        }
    48→    }
    49→    
    50→    /// Get the computed mean (after evaluation).
    51→    pub fn mean(&self) -> Option<f64> {
    52→        self.mean
    53→    }
    54→    
    55→    /// Get the computed standard deviation (after evaluation).
    56→    pub fn std(&self) -> Option<f64> {
    57→        self.std
    58→    }
    59→}
    60→
    61→impl BasisFunction for Scale {
    62→    fn name(&self) -> &str {
    63→        &self.name
    64→    }
    65→    
    66→    fn nbasis(&self) -> usize {
    67→        1
    68→    }
    69→    
    70→    fn evaluate(&self, x: &ArrayView1<f64>) -> Result<Array, ValidationError> {
    71→        if x.is_empty() {
    72→            return Err(ValidationError::EmptyArray);
    73→        }
    74→        
    75→        let n = x.len();
    76→        let mut result = Array2::zeros((n, 1));
    77→        
    78→        // Copy input values
    79→        for (i, &val) in x.iter().enumerate() {
    80→            result[[i, 0]] = val;
    81→        }
    82→        
    83→        // Compute statistics
    84→        let mean = x.sum() / n as f64;
    85→        let variance = x.mapv(|v| (v - mean).powi(2)).sum() / n as f64;
    86→        let std = variance.sqrt();
    87→        
    88→        // Store statistics (requires mutable self in real implementation)
    89→        // For now, we'll compute inline
    90→        
    91→        // Apply transformations
    92→        if self.center {
    93→            for i in 0..n {
    94→                result[[i, 0]] -= mean;
    95→            }
    96→        }
    97→        
    98→        if self.scale && std > 0.0 {
    99→            for i in 0..n {
   100→                result[[i, 0]] /= std;
   101→            }
   102→        }
   103→        
   104→        Ok(result)
   105→    }
   106→    
   107→    fn predict(&self, x: &ArrayView1<f64>, coef: Option<&ArrayView1<f64>>) -> Result<Vector, ValidationError> {
   108→        let basis = self.evaluate(x)?;
   109→        if let Some(c) = coef {
   110→            if c.len() != self.nbasis() {
   111→                return Err(ValidationError::LengthMismatch {
   112→                    expected: self.nbasis(),
   113→                    actual: c.len(),
   114→                });
   115→            }
   116→            Ok(basis.dot(c))
   117→        } else {
   118→            Ok(basis.column(0).to_owned())
   119→        }
   120→    }
   121→}
