   123→/// Robust scaling transformation.
   124→///
   125→/// Centers at median and scales by MAD (median absolute deviation)
   126→/// or IQR (interquartile range).
   127→#[derive(Debug, Clone)]
   128→pub struct RobustScale {
   129→    /// Whether to center at median.
   130→    pub center: bool,
   131→    /// Scaling method.
   132→    pub scale_method: RobustScaleMethod,
   133→    /// Constant for MAD scaling (1.4826 for normal distribution).
   134→    pub constant: f64,
   135→    /// Name for the transformation.
   136→    pub name: String,
   137→    /// Computed median (after evaluation).
   138→    median: Option<f64>,
   139→    /// Computed scale factor (after evaluation).
   140→    scale_factor: Option<f64>,
   141→}
   142→
   143→/// Scaling method for robust scaling.
   144→#[derive(Debug, Clone, Copy, PartialEq)]
   145→pub enum RobustScaleMethod {
   146→    /// Median Absolute Deviation.
   147→    Mad,
   148→    /// Interquartile Range.
   149→    Iqr,
   150→}
   151→
   152→impl RobustScale {
   153→    /// Create a new RobustScale transformation.
   154→    pub fn new(center: bool, scale_method: RobustScaleMethod) -> Self {
   155→        Self {
   156→            center,
   157→            scale_method,
   158→            constant: 1.4826, // Standard constant for normal distribution
   159→            name: "robustscale".to_string(),
   160→            median: None,
   161→            scale_factor: None,
   162→        }
   163→    }
   164→    
   165→    /// Create with custom constant.
   166→    pub fn with_constant(center: bool, scale_method: RobustScaleMethod, constant: f64) -> Self {
   167→        Self {
   168→            center,
   169→            scale_method,
   170→            constant,
   171→            name: "robustscale".to_string(),
   172→            median: None,
   173→            scale_factor: None,
   174→        }
   175→    }
   176→    
   177→    /// Get the computed median (after evaluation).
   178→    pub fn median(&self) -> Option<f64> {
   179→        self.median
   180→    }
   181→    
   182→    /// Get the computed scale factor (after evaluation).
   183→    pub fn scale_factor(&self) -> Option<f64> {
   184→        self.scale_factor
   185→    }
   186→}
   187→
   188→impl BasisFunction for RobustScale {
   189→    fn name(&self) -> &str {
   190→        &self.name
   191→    }
   192→    
   193→    fn nbasis(&self) -> usize {
   194→        1
   195→    }
   196→    
   197→    fn evaluate(&self, x: &ArrayView1<f64>) -> Result<Array, ValidationError> {
   198→        if x.is_empty() {
   199→            return Err(ValidationError::EmptyArray);
   200→        }
   201→        
   202→        let n = x.len();
   203→        let mut result = Array2::zeros((n, 1));
   204→        
   205→        // Copy and sort for median calculation
   206→        let mut sorted: Vec<f64> = x.to_vec();
   207→        sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
   208→        
   209→        // Compute median
   210→        let median = if n % 2 == 0 {
   211→            (sorted[n / 2 - 1] + sorted[n / 2]) / 2.0
   212→        } else {
   213→            sorted[n / 2]
   214→        };
   215→        
   216→        // Compute scale factor based on method
   217→        let scale_factor = match self.scale_method {
   218→            RobustScaleMethod::Mad => {
   219→                // Median absolute deviation
   220→                let mut deviations: Vec<f64> = x.iter()
   221→                    .map(|&v| (v - median).abs())
   222→                    .collect();
   223→                deviations.sort_by(|a, b| a.partial_cmp(b).unwrap());
   224→                
   225→                let mad = if n % 2 == 0 {
   226→                    (deviations[n / 2 - 1] + deviations[n / 2]) / 2.0
   227→                } else {
   228→                    deviations[n / 2]
   229→                };
   230→                
   231→                mad * self.constant
   232→            }
   233→            RobustScaleMethod::Iqr => {
   234→                // Interquartile range
   235→                let q1_idx = n / 4;
   236→                let q3_idx = (3 * n) / 4;
   237→                
   238→                let q1 = if n % 4 == 0 {
   239→                    (sorted[q1_idx - 1] + sorted[q1_idx]) / 2.0
   240→                } else {
   241→                    sorted[q1_idx]
   242→                };
   243→                
   244→                let q3 = if (3 * n) % 4 == 0 {
   245→                    (sorted[q3_idx - 1] + sorted[q3_idx]) / 2.0
   246→                } else {
   247→                    sorted[q3_idx]
   248→                };
   249→                
   250→                q3 - q1
   251→            }
   252→        };
   253→        
   254→        // Apply transformations
   255→        for (i, &val) in x.iter().enumerate() {
   256→            result[[i, 0]] = val;
   257→            
   258→            if self.center {
   259→                result[[i, 0]] -= median;
   260→            }
   261→            
   262→            if scale_factor > 0.0 {
   263→                result[[i, 0]] /= scale_factor;
   264→            }
   265→        }
   266→        
   267→        Ok(result)
   268→    }
   269→    
   270→    fn predict(&self, x: &ArrayView1<f64>, coef: Option<&ArrayView1<f64>>) -> Result<Vector, ValidationError> {
   271→        let basis = self.evaluate(x)?;
   272→        if let Some(c) = coef {
   273→            if c.len() != self.nbasis() {
   274→                return Err(ValidationError::LengthMismatch {
   275→                    expected: self.nbasis(),
   276→                    actual: c.len(),
   277→                });
   278→            }
   279→            Ok(basis.dot(c))
   280→        } else {
   281→            Ok(basis.column(0).to_owned())
   282→        }
   283→    }
   284→}
