   358→/// Group-wise scaling transformation.
   359→///
   360→/// Centers and scales values within each group separately.
   361→#[derive(Debug, Clone)]
   362→pub struct ScaleWithin {
   363→    /// Group indicators for each observation.
   364→    pub groups: Vec<String>,
   365→    /// Whether to center within groups.
   366→    pub center: bool,
   367→    /// Whether to scale within groups.
   368→    pub scale: bool,
   369→    /// Name for the transformation.
   370→    pub name: String,
   371→    /// Group statistics (after evaluation).
   372→    group_stats: Option<std::collections::HashMap<String, GroupStats>>,
   373→}
   374→
   375→/// Statistics for a group in ScaleWithin transformation.
   376→#[derive(Debug, Clone)]
   377→pub struct GroupStats {
   378→    /// Group mean
   379→    pub mean: f64,
   380→    /// Group standard deviation
   381→    pub std: f64,
   382→    /// Number of observations in group
   383→    pub n: usize,
   384→}
   385→
   386→impl ScaleWithin {
   387→    /// Create a new ScaleWithin transformation.
   388→    pub fn new(groups: Vec<String>, center: bool, scale: bool) -> Self {
   389→        Self {
   390→            groups,
   391→            center,
   392→            scale,
   393→            name: "scalewithin".to_string(),
   394→            group_stats: None,
   395→        }
   396→    }
   397→    
   398→    /// Get group statistics (after evaluation).
   399→    pub fn group_stats(&self) -> Option<&std::collections::HashMap<String, GroupStats>> {
   400→        self.group_stats.as_ref()
   401→    }
   402→}
   403→
   404→impl BasisFunction for ScaleWithin {
   405→    fn name(&self) -> &str {
   406→        &self.name
   407→    }
   408→    
   409→    fn nbasis(&self) -> usize {
   410→        1
   411→    }
   412→    
   413→    fn evaluate(&self, x: &ArrayView1<f64>) -> Result<Array, ValidationError> {
   414→        if x.is_empty() {
   415→            return Err(ValidationError::EmptyArray);
   416→        }
   417→        
   418→        if x.len() != self.groups.len() {
   419→            return Err(ValidationError::LengthMismatch {
   420→                expected: self.groups.len(),
   421→                actual: x.len(),
   422→            });
   423→        }
   424→        
   425→        let n = x.len();
   426→        let mut result = Array2::zeros((n, 1));
   427→        
   428→        // Collect unique groups
   429→        let mut unique_groups: Vec<String> = self.groups.clone();
   430→        unique_groups.sort();
   431→        unique_groups.dedup();
   432→        
   433→        // Process each group
   434→        let mut group_stats = std::collections::HashMap::new();
   435→        
   436→        for group in &unique_groups {
   437→            // Find indices for this group
   438→            let indices: Vec<usize> = self.groups.iter()
   439→                .enumerate()
   440→                .filter(|(_, g)| *g == group)
   441→                .map(|(i, _)| i)
   442→                .collect();
   443→            
   444→            if indices.is_empty() {
   445→                continue;
   446→            }
   447→            
   448→            // Collect group data
   449→            let group_data: Vec<f64> = indices.iter()
   450→                .map(|&i| x[i])
   451→                .collect();
   452→            
   453→            // Compute group statistics
   454→            let n_group = group_data.len() as f64;
   455→            let mean = group_data.iter().sum::<f64>() / n_group;
   456→            let variance = group_data.iter()
   457→                .map(|&v| (v - mean).powi(2))
   458→                .sum::<f64>() / n_group;
   459→            let std = variance.sqrt();
   460→            
   461→            group_stats.insert(group.clone(), GroupStats {
   462→                mean,
   463→                std,
   464→                n: group_data.len(),
   465→            });
   466→            
   467→            // Transform group data
   468→            for (j, &idx) in indices.iter().enumerate() {
   469→                let mut val = group_data[j];
   470→                
   471→                if self.center {
   472→                    val -= mean;
   473→                }
   474→                
   475→                if self.scale && std > 0.0 {
   476→                    val /= std;
   477→                }
   478→                
   479→                result[[idx, 0]] = val;
   480→            }
   481→        }
   482→        
   483→        Ok(result)
   484→    }
   485→    
   486→    fn predict(&self, x: &ArrayView1<f64>, coef: Option<&ArrayView1<f64>>) -> Result<Vector, ValidationError> {
   487→        let basis = self.evaluate(x)?;
   488→        if let Some(c) = coef {
   489→            if c.len() != self.nbasis() {
   490→                return Err(ValidationError::LengthMismatch {
   491→                    expected: self.nbasis(),
   492→                    actual: c.len(),
   493→                });
   494→            }
   495→            Ok(basis.dot(c))
   496→        } else {
   497→            Ok(basis.column(0).to_owned())
   498→        }
   499→    }
   500→}
