   502→/// Standardized transformation with fit/transform pattern.
   503→///
   504→/// Similar to Scale but allows fitting statistics on one dataset
   505→/// and applying to another.
   506→#[derive(Debug, Clone)]
   507→pub struct Standardized {
   508→    /// Whether to center (subtract mean).
   509→    pub center: bool,
   510→    /// Whether to scale (divide by standard deviation).
   511→    pub scale: bool,
   512→    /// Name for the transformation.
   513→    pub name: String,
   514→    /// Fitted mean.
   515→    mean: Option<f64>,
   516→    /// Fitted standard deviation.
   517→    std: Option<f64>,
   518→}
   519→
   520→impl Standardized {
   521→    /// Create a new Standardized transformation.
   522→    pub fn new(center: bool, scale: bool) -> Self {
   523→        Self {
   524→            center,
   525→            scale,
   526→            name: "standardized".to_string(),
   527→            mean: None,
   528→            std: None,
   529→        }
   530→    }
   531→    
   532→    /// Fit the standardization parameters.
   533→    pub fn fit(&mut self, x: &[f64]) -> Result<(), ValidationError> {
   534→        if x.is_empty() {
   535→            return Err(ValidationError::EmptyArray);
   536→        }
   537→        
   538→        let n = x.len() as f64;
   539→        
   540→        if self.center {
   541→            self.mean = Some(x.iter().sum::<f64>() / n);
   542→        } else {
   543→            self.mean = Some(0.0);
   544→        }
   545→        
   546→        if self.scale {
   547→            let mean = self.mean.unwrap();
   548→            let variance = x.iter()
   549→                .map(|&v| (v - mean).powi(2))
   550→                .sum::<f64>() / n;
   551→            let std = variance.sqrt();
   552→            
   553→            self.std = Some(if std == 0.0 { 1.0 } else { std });
   554→        } else {
   555→            self.std = Some(1.0);
   556→        }
   557→        
   558→        Ok(())
   559→    }
   560→    
   561→    /// Check if the transformer has been fitted.
   562→    pub fn is_fitted(&self) -> bool {
   563→        self.mean.is_some() && self.std.is_some()
   564→    }
   565→    
   566→    /// Get the fitted mean.
   567→    pub fn fitted_mean(&self) -> Option<f64> {
   568→        self.mean
   569→    }
   570→    
   571→    /// Get the fitted standard deviation.
   572→    pub fn fitted_std(&self) -> Option<f64> {
   573→        self.std
   574→    }
   575→}
   576→
   577→impl BasisFunction for Standardized {
   578→    fn name(&self) -> &str {
   579→        &self.name
   580→    }
   581→    
   582→    fn nbasis(&self) -> usize {
   583→        1
   584→    }
   585→    
   586→    fn evaluate(&self, x: &ArrayView1<f64>) -> Result<Array, ValidationError> {
   587→        if x.is_empty() {
   588→            return Err(ValidationError::EmptyArray);
   589→        }
   590→        
   591→        let n = x.len();
   592→        let mut result = Array2::zeros((n, 1));
   593→        
   594→        // Use fitted parameters or fit on input
   595→        let (mean, std) = if self.is_fitted() {
   596→            (self.mean.unwrap(), self.std.unwrap())
   597→        } else {
   598→            // Auto-fit on input (note: this requires mutable self in practice)
   599→            let n_f = n as f64;
   600→            let mean = if self.center {
   601→                x.sum() / n_f
   602→            } else {
   603→                0.0
   604→            };
   605→            
   606→            let std = if self.scale {
   607→                let variance = x.mapv(|v| (v - mean).powi(2)).sum() / n_f;
   608→                let s = variance.sqrt();
   609→                if s == 0.0 { 1.0 } else { s }
   610→            } else {
   611→                1.0
   612→            };
   613→            
   614→            (mean, std)
   615→        };
   616→        
   617→        // Apply transformation
   618→        for (i, &val) in x.iter().enumerate() {
   619→            result[[i, 0]] = (val - mean) / std;
   620→        }
   621→        
   622→        Ok(result)
   623→    }
   624→    
   625→    fn predict(&self, x: &ArrayView1<f64>, coef: Option<&ArrayView1<f64>>) -> Result<Vector, ValidationError> {
   626→        let basis = self.evaluate(x)?;
   627→        if let Some(c) = coef {
   628→            if c.len() != self.nbasis() {
   629→                return Err(ValidationError::LengthMismatch {
   630→                    expected: self.nbasis(),
   631→                    actual: c.len(),
   632→                });
   633→            }
   634→            Ok(basis.dot(c))
   635→        } else {
   636→            Ok(basis.column(0).to_owned())
   637→        }
   638→    }
   639→}
