   270→        } else {
   271→            base_cond_tags
   272→        };
   273→        
   274→        Ok(final_cond_tags)
   275→    }
   276→    
   277→    /// Get the number of basis functions for this term.
   278→    fn nbasis(&self) -> usize {
   279→        // This would need to be implemented based on how basis functions are stored
   280→        // For now, return 1 as default
