   356→        
   357→        let cond = EventFactor::new("condition", onsets.to_vec(), cond_values, durations.to_vec()).unwrap();
   358→        let block = EventFactor::new("block", onsets.to_vec(), block_values, durations.to_vec()).unwrap();
   359→        
