   361→        
   362→        let cells = term.cells(false).unwrap();
   363→        assert_eq!(cells.columns, vec!["condition", "block"]);
   364→        assert_eq!(cells.rows.len(), 4); // All combinations
   365→        assert_eq!(cells.counts, vec![1, 1, 1, 1]); // One of each
   366→    }
   367→}

