     1→//! Naming utilities for design matrix column names.
     2→//!
     3→//! This module implements the naming scheme from the R fmridesign package,
     4→//! ensuring consistent and R-compatible column names.
     5→
     6→use regex::Regex;
     7→use std::collections::HashMap;
     8→use lazy_static::lazy_static;
     9→
    10→lazy_static! {
    11→    /// Regex for invalid characters in names
    12→    static ref INVALID_CHARS: Regex = Regex::new(r"[^a-zA-Z0-9._]").unwrap();
    13→    /// Regex for multiple underscores
    14→    static ref MULTI_UNDERSCORE: Regex = Regex::new(r"_+").unwrap();
    15→}
    16→
    17→/// Zero-pad numbers for consistent width.
    18→///
    19→/// # Arguments
    20→/// * `i` - Number to pad
    21→/// * `n_total` - Total count (determines width)
    22→///
    23→/// # Returns
    24→/// Zero-padded string
    25→pub fn zeropad(i: usize, n_total: usize) -> String {
    26→    let width = if n_total < 1 {
    27→        1
    28→    } else {
    29→        let log_width = n_total.to_string().len();
    30→        if n_total > 1 {
    31→            log_width.max(2)
    32→        } else {
    33→            log_width
    34→        }
    35→    };
    36→    
    37→    format!("{:0width$}", i, width = width)
    38→}
    39→
    40→/// Sanitize strings for use in R/Python names.
    41→///
    42→/// # Arguments
    43→/// * `x` - String to sanitize
    44→/// * `allow_dot` - If false, replace dots with underscores
    45→///
    46→/// # Returns
    47→/// Sanitized string
    48→pub fn sanitize(x: &str, allow_dot: bool) -> String {
    49→    // Replace invalid characters
    50→    let mut sanitized = INVALID_CHARS.replace_all(x, "_").to_string();
    51→    
    52→    // Ensure doesn't start with digit or underscore
    53→    if let Some(first_char) = sanitized.chars().next() {
    54→        if first_char.is_numeric() || first_char == '_' {
    55→            sanitized = format!("X{}", sanitized);
    56→        }
    57→    }
    58→    
    59→    // Handle dots
    60→    if !allow_dot {
    61→        sanitized = sanitized.replace('.', "_");
    62→        // Replace multiple underscores with single
    63→        sanitized = MULTI_UNDERSCORE.replace_all(&sanitized, "_").to_string();
    64→        // Remove leading/trailing underscores
    65→        sanitized = sanitized.trim_matches('_').to_string();
    66→    }
    67→    
    68→    // Ensure not empty
    69→    if sanitized.is_empty() {
    70→        sanitized = "X".to_string();
    71→    }
    72→    
    73→    sanitized
    74→}
    75→
    76→/// Sanitize factor level.
    77→///
    78→/// Similar to sanitize() but removes leading X for numeric levels.
    79→///
    80→/// # Arguments
    81→/// * `level` - Factor level to sanitize
    82→///
    83→/// # Returns
    84→/// Sanitized level
    85→pub fn sanitize_level(level: &str) -> String {
    86→    let sanitized = sanitize(level, true);
    87→    
    88→    // If original started with digit and sanitized starts with X, remove it
    89→    if let Some(first_char) = level.chars().next() {
    90→        if first_char.is_numeric() && sanitized.starts_with('X') {
    91→            return sanitized[1..].to_string();
    92→        }
    93→    }
    94→    
    95→    sanitized
    96→}
    97→
    98→/// Create basis function suffix.
    99→///
   100→/// # Arguments
   101→/// * `j` - Basis index (1-based)
   102→/// * `nb` - Total number of basis functions
   103→///
   104→/// # Returns
   105→/// Suffix like '_b01', '_b02'
   106→pub fn basis_suffix(j: usize, nb: usize) -> String {
   107→    format!("_b{}", zeropad(j, nb))
   108→}
   109→
   110→/// Create feature suffix.
   111→///
   112→/// # Arguments
   113→/// * `j` - Feature index (1-based)
   114→/// * `nf` - Total number of features
   115→///
   116→/// # Returns
   117→/// Suffix like 'f01', 'f02'
   118→pub fn feature_suffix(j: usize, nf: usize) -> String {
   119→    format!("f{}", zeropad(j, nf))
   120→}
   121→
   122→/// Make tags unique using # separator.
   123→///
   124→/// # Arguments
   125→/// * `tags` - Tags to make unique
   126→///
   127→/// # Returns
   128→/// Unique tags
   129→pub fn make_unique_tags(tags: &[String]) -> Vec<String> {
   130→    let mut seen: HashMap<String, usize> = HashMap::new();
   131→    let mut result = Vec::new();
   132→    
   133→    for tag in tags {
   134→        if let Some(count) = seen.get_mut(tag) {
   135→            *count += 1;
   136→            result.push(format!("{}#{}", tag, *count - 1));
   137→        } else {
   138→            seen.insert(tag.clone(), 1);
   139→            result.push(tag.clone());
   140→        }
   141→    }
   142→    
   143→    result
   144→}
   145→
   146→/// Generate term tag.
   147→///
   148→/// # Arguments
   149→/// * `term_name` - Explicit term name/id
   150→/// * `event_names` - Event variable names
   151→/// * `hrf_name` - HRF name (for suffix)
   152→/// * `basis_type` - Basis type (e.g., 'poly', 'spline')
   153→/// * `existing_tags` - Already used tags for uniqueness
   154→///
   155→/// # Returns
   156→/// Term tag (None for identity terms)
   157→pub fn make_term_tag(
   158→    term_name: Option<&str>,
   159→    event_names: Option<&[String]>,
   160→    _hrf_name: Option<&str>,
   161→    basis_type: Option<&str>,
   162→    existing_tags: Option<&[String]>,
   163→) -> Option<String> {
   164→    let tag_base = if let Some(name) = term_name {
   165→        // Explicit name provided
   166→        sanitize(name, false)
   167→    } else if let Some(names) = event_names {
   168→        if names.is_empty() {
   169→            return None;
   170→        }
   171→        
   172→        // Build from event names
   173→        if let (Some(basis), true) = (basis_type, names.len() == 1) {
   174→            // Special handling for basis functions
   175→            let var_name = sanitize(&names[0], false);
   176→            let basis_prefix = match basis.to_lowercase().as_str() {
   177→                "poly" | "polynomial" => "poly",
   178→                "bspline" | "spline" => "bs",
   179→                "scale" => "z",
   180→                "standardized" => "std",
   181→                "robustscale" => "robz",
   182→                _ => basis,
   183→            };
   184→            format!("{}_{}", basis_prefix, var_name)
   185→        } else {
   186→            // Join event names
   187→            names.iter()
   188→                .map(|name| sanitize(name, false))
   189→                .collect::<Vec<_>>()
   190→                .join("_")
   191→        }
   192→    } else {
   193→        // No information - return None (identity term)
   194→        return None;
   195→    };
   196→    
   197→    // Ensure not empty
   198→    let tag_base = if tag_base.is_empty() {
   199→        "empty_id_tag".to_string()
   200→    } else {
   201→        tag_base
   202→    };
   203→    
   204→    // Make unique if needed
   205→    if let Some(existing) = existing_tags {
   206→        let mut all_tags: Vec<String> = existing.to_vec();
   207→        all_tags.push(tag_base);
   208→        let unique_tags = make_unique_tags(&all_tags);
   209→        Some(unique_tags.last().unwrap().clone())
   210→    } else {
   211→        Some(tag_base)
   212→    }
   213→}
   214→
   215→/// Create factor level token.
   216→///
   217→/// # Arguments
   218→/// * `var` - Variable name
   219→/// * `level` - Level name
   220→///
   221→/// # Returns
   222→/// Token like 'var.level'
   223→pub fn level_token(var: &str, level: &str) -> String {
   224→    let s_var = sanitize(var, true);
   225→    let s_level = sanitize_level(level);
   226→    format!("{}.{}", s_var, s_level)
   227→}
   228→
   229→/// Sanitize continuous column name token.
   230→///
   231→/// # Arguments
   232→/// * `colname` - Proposed column name
   233→///
   234→/// # Returns
   235→/// Sanitized token
   236→pub fn continuous_token(colname: &str) -> String {
   237→    sanitize(colname, true)
   238→}
   239→
   240→/// Combine tokens into condition tag.
   241→///
   242→/// # Arguments
   243→/// * `tokens` - Tokens to combine
   244→///
   245→/// # Returns
   246→/// Combined condition tag
   247→pub fn make_cond_tag(tokens: &[String]) -> String {
   248→    tokens.join("_")
   249→}
   250→
   251→/// Add basis suffix to condition tags if needed.
   252→///
   253→/// # Arguments
   254→/// * `cond_tags` - Base condition tags
   255→/// * `nb` - Number of basis functions
   256→///
   257→/// # Returns
   258→/// Expanded tags with basis suffixes
   259→pub fn add_basis_suffix(cond_tags: &[String], nb: usize) -> Vec<String> {
   260→    if nb <= 1 {
   261→        return cond_tags.to_vec();
   262→    }
   263→    
   264→    // Expand each tag with basis suffixes
   265→    let mut result = Vec::new();
   266→    for tag in cond_tags {
   267→        for j in 1..=nb {
   268→            result.push(format!("{}{}", tag, basis_suffix(j, nb)));
   269→        }
   270→    }
   271→    
   272→    result
   273→}
   274→
   275→/// Compose final column names.
   276→///
   277→/// This is the single source of truth for creating design matrix column names.
   278→///
   279→/// # Arguments
   280→/// * `term_tag` - Sanitized, unique term tag (None for identity terms)
   281→/// * `cond_tags` - Base condition tags (without basis suffix)
   282→/// * `nb` - Number of basis functions
   283→///
   284→/// # Returns
   285→/// Final column names
   286→pub fn make_column_names(
   287→    term_tag: Option<&str>,
   288→    cond_tags: &[String],
   289→    nb: usize,
   290→) -> Vec<String> {
   291→    // Add basis suffix if needed
   292→    let full_cond_tags = add_basis_suffix(cond_tags, nb);
   293→    
   294→    // Combine term tag and condition tags
   295→    if let Some(tag) = term_tag {
   296→        // Normal case: term_tag_condition_tag[_b##]
   297→        full_cond_tags.iter()
   298→            .map(|cond_tag| format!("{}_{}", tag, cond_tag))
   299→            .collect()
   300→    } else {
   301→        // Identity term - use condition tags directly
   302→        full_cond_tags
   303→    }
   304→}
   305→
   306→/// Ensure column names are unique.
   307→///
   308→/// Uses R-style suffixing (.1, .2, etc.) for duplicates.
   309→///
   310→/// # Arguments
   311→/// * `colnames` - Column names to make unique
   312→///
   313→/// # Returns
   314→/// Unique column names
   315→pub fn make_unique_colnames(colnames: &[String]) -> Vec<String> {
   316→    let mut seen: HashMap<String, usize> = HashMap::new();
   317→    let mut result = Vec::new();
   318→    
   319→    for name in colnames {
   320→        if let Some(count) = seen.get_mut(name) {
   321→            *count += 1;
   322→            result.push(format!("{}.{}", name, count));
   323→        } else {
   324→            seen.insert(name.clone(), 0);
   325→            result.push(name.clone());
   326→        }
   327→    }
   328→    
   329→    result
   330→}
   331→
   332→/// Convert long column names to short names.
   333→///
   334→/// # Arguments
   335→/// * `longnames_list` - Long column names to shorten
   336→/// * `acronym` - Acronym to use for the model (default: first letters)
   337→///
   338→/// # Returns
   339→/// Shortened column names
   340→pub fn shortnames(longnames_list: &[String], acronym: Option<&str>) -> Vec<String> {
   341→    if longnames_list.is_empty() {
   342→        return Vec::new();
   343→    }
   344→    
   345→    // Extract unique term tags (before underscores)
   346→    let mut term_tags: Vec<String> = longnames_list.iter()
   347→        .filter_map(|name| {
   348→            name.split('_').next().map(|s| s.to_string())
   349→        })
   350→        .collect::<std::collections::HashSet<_>>()
   351→        .into_iter()
   352→        .collect();
   353→    term_tags.sort();
   354→    
   355→    // Create short version of each term tag
   356→    let mut term_map = HashMap::new();
   357→    if let Some(acr) = acronym {
   358→        // Use provided acronym
   359→        for (i, tag) in term_tags.iter().enumerate() {
   360→            let short = if term_tags.len() > 1 {
   361→                format!("{}{}", acr, i + 1)
   362→            } else {
   363→                acr.to_string()
   364→            };
   365→            term_map.insert(tag.clone(), short);
   366→        }
   367→    } else {
   368→        // Generate from first letters
   369→        for tag in &term_tags {
   370→            // Extract capital letters or first letter of each word part
   371→            let short: String = tag.chars()
   372→                .filter(|c| c.is_uppercase())
   373→                .collect();
   374→            
   375→            let short = if short.is_empty() {
   376→                // No capitals, use first letter of each underscore-separated part
   377→                let parts: Vec<&str> = tag.split('_').collect();
   378→                let short: String = parts.iter()
   379→                    .filter_map(|p| p.chars().next())
   380→                    .map(|c| c.to_uppercase().to_string())
   381→                    .collect();
   382→                
   383→                if short.is_empty() {
   384→                    // Fallback to first 3 chars
   385→                    tag.chars().take(3).collect::<String>().to_uppercase()
   386→                } else {
   387→                    short
   388→                }
   389→            } else {
   390→                short
   391→            };
   392→            
   393→            term_map.insert(tag.clone(), short);
   394→        }
   395→    }
   396→    
   397→    // Apply mapping to create short names
   398→    longnames_list.iter()
   399→        .map(|name| {
   400→            if let Some((term_tag, rest)) = name.split_once('_') {
   401→                if let Some(short) = term_map.get(term_tag) {
   402→                    format!("{}_{}", short, rest)
   403→                } else {
   404→                    name.clone()
   405→                }
   406→            } else {
   407→                name.clone()
   408→            }
   409→        })
   410→        .collect()
   411→}
   412→
   413→/// Alias for make_column_names for consistency.
   414→///
   415→/// # Arguments
   416→/// * `term_tag` - Sanitized, unique term tag (None for identity terms)
   417→/// * `cond_tags` - Base condition tags (without basis suffix)
   418→/// * `nb` - Number of basis functions
   419→///
   420→/// # Returns
   421→/// Long column names
   422→pub fn longnames(
   423→    term_tag: Option<&str>,
   424→    cond_tags: &[String],
   425→    nb: usize,
   426→) -> Vec<String> {
   427→    make_column_names(term_tag, cond_tags, nb)
   428→}
