   430→#[cfg(test)]
   431→mod tests {
   432→    use super::*;
   433→    
   434→    #[test]
   435→    fn test_zeropad() {
   436→        assert_eq!(zeropad(1, 10), "01");
   437→        assert_eq!(zeropad(10, 10), "10");
   438→        assert_eq!(zeropad(1, 100), "001");
   439→        assert_eq!(zeropad(1, 1), "1");
