   441→    
   442→    #[test]
   443→    fn test_sanitize() {
   444→        assert_eq!(sanitize("hello world", true), "hello_world");
   445→        assert_eq!(sanitize("123abc", true), "X123abc");
   446→        assert_eq!(sanitize("_test", true), "X_test");
   447→        assert_eq!(sanitize("test.name", false), "test_name");
   448→        assert_eq!(sanitize("test__name", false), "test_name");
