//! Formula parsing and DSL for model specification.

pub mod parser;
pub mod builder;
pub mod term;
pub mod dsl;
pub mod event_model;
pub mod context;

pub use parser::{FormulaExpr, FormulaParser, parse_formula};
pub use builder::ExprBuilder;
pub use term::{Term, TermBuilder, HrfSpec, TermParam, term, interaction};
pub use dsl::{EventVar, event, hrf, HrfNamespace};
pub use event_model::{event_model, EventModelBuilder};
pub use context::{FormulaContext, FormulaContextBuilder, Variable, DataSource, TermDataBinding, parse_formula_with_context};

use crate::types::ValidationError;

/// Formula specification.
#[derive(Debug, Clone)]
pub struct Formula {
    /// Formula string
    pub formula: String,
}

impl Formula {
    /// Parse a formula string.
    pub fn parse(formula: &str) -> Result<Self, ValidationError> {
        // TODO: Implement formula parsing
        Ok(Self {
            formula: formula.to_string(),
        })
    }
}

/// Builder for creating formulas.
#[derive(Debug)]
pub struct FormulaBuilder {
    terms: Vec<String>,
}

impl FormulaBuilder {
    /// Create a new formula builder.
    pub fn new() -> Self {
        Self {
            terms: Vec::new(),
        }
    }

    /// Add a term to the formula.
    pub fn add_term<S: Into<String>>(mut self, term: S) -> Self {
        self.terms.push(term.into());
        self
    }

    /// Build the formula.
    pub fn build(self) -> Formula {
        Formula {
            formula: self.terms.join(" + "),
        }
    }
}

impl Default for FormulaBuilder {
    fn default() -> Self {
        Self::new()
    }
}

